import Tools from "./Tools";

export default class MethodExtension { }

declare global {
    namespace cc {
        interface Node {
            /**
             * 获取当前节点位置在目标节点下的局部坐标(三维)
             */
            changeV3Pos(parentNode: cc.Node): cc.Vec3;
            
            /**
             * 获取当前节点位置在目标节点下的局部坐标（二维）
             */
            changeV2Pos(parentNode: cc.Node): cc.Vec2;
        }

        interface ScrollView {
            isCancelTouchMove: boolean;
        }
    }
    interface Number {
        /** 转boolean型 ， 0是false，其他是true */
        toBoolean(): Boolean;
        /** number 奇偶性判断 1是奇数 0是偶数 */
        parity(): number;
        /** 去多少位小数 */
        toRound(num : number);
    }

    interface Math {
        /** 判断2个数字的符号 true相等  false 不相等 */
        symbol(x: number, y: number): Boolean;
    }

    interface Array<T> {
        /** 深拷贝 */
        deepCopy(): T[];
        /** 数组中抽取1个随机数 */
        getRandomElement(): T;
        /** 数组中抽取数量随机数 */
        getRandomElements(count: number): T[];
        /** 清空 */
        clear();
        /** 移除1个key值 , 深拷贝，不改变原数组 */
        removeKey(key: string): T[];
        /** 移除N个key值 , 深拷贝, 不改变原数组 */
        removeKeys(keys: string[]): T[];
        /** 移除N个key值 , 改变原数组 */
        removeKeysBySelf(keys: string[]): void;
    }

    interface ArrayConstructor {
        /** 深拷贝 */
        deepCopy(_array: any[]): any[];
    }

    interface Date {
        /** 格式化 默认yyyy-MM-dd-HH-mm-ss*/
        format(format?: string): string;
        /**
         * 相差天数
         * @param date 时间戳
         */
        diffday(date: number): number;
        /**
         * 时间相加
         * @param date 毫秒数
         */
        add(date: number): Date;
        /**
         * 时间相减
         * @param date 毫秒数
         */
        subtract(date: number): Date;
    }

    interface String {
        /** 在当前字符串前拼接字符串 */
        AddHead(str: string): string;
        /** 在当前字符串后拼接字符串 */
        AddEnd(str: string): string;
        /** 全部替換 */
        replaceAll(s1 : string , s2 : string);
    }

    function md5(str: string): string;

    /** 监听成员变量修改位置 DebugSet(node,'x') */ 
    function DebugSet(obj:object, attr:string, func?: ()=>any): void;
    function DebugGet(obj:object, attr:string): void;
    /** Debug: 打印调用栈 */
    function getStackTrace(): string;
}

// 非Creator编辑器环境
if(!window['CC_EDITOR']){
        
    /** 判断2个数字的符号是否相等 */
    Math.symbol = function (x: number, y: number): boolean {
        return (x ^ y) > 0;
    }

    Number.prototype.toBoolean = function (): Boolean {
        return !!this;
    }

    Number.prototype.parity = function (): number {
        return this & 1;
    }

    
    /** PC端启动开启调试 */
    if(cc.sys.platform === cc.sys.DESKTOP_BROWSER){
        // Debug: number == (NaN || Infinity) 时主动报错与断点
        Number.prototype.toRound = function (e : number) : number {
            if (!isFinite(this)) {
                console.error("Number is NaN or Infinity !!");
                debugger;
            }
            const r = Math.pow(10 , e);
            return Math.round(this * r) / r; 
        }
    }else{
        Number.prototype.toRound = function (e : number) : number {
            const r = Math.pow(10 , e);
            return Math.round(this * r) / r; 
        }
    }

    
    if (!cc.Node.prototype.changeV3Pos)  {
        /** 获取当前节点位置在目标节点下的局部坐标(三维) */
        cc.Node.prototype.changeV3Pos = function(parentNode) {
            return parentNode.convertToNodeSpaceAR(this.convertToWorldSpaceAR(cc.Vec3.ZERO));
        }
    }

    if (!cc.Node.prototype.changeV2Pos)  {
        /** 获取当前节点位置在目标节点下的局部坐标（二维） */
        cc.Node.prototype.changeV2Pos = function(parentNode) {
            return parentNode.convertToNodeSpaceAR(this.convertToWorldSpaceAR(cc.Vec2.ZERO));
        }
    }

    String.prototype.AddHead = function (str: string): string {
        return str + this;
    }

    String.prototype.AddEnd = function (str: string): string {
        return this.join(str);
    }

    String.prototype.replaceAll = function(s1, s2) {
        return this.replace(new RegExp(s1, "gm"), s2);
    }

    Array.deepCopy = function <T>(_array: Array<T>): T[] {
        return Tools.CopyObject(_array);
    }

    Object.defineProperty(Array.prototype, "deepCopy", {
        value: function (): any[] {
            let that = this;
            let r = Tools.CopyObject(that);
            that = null;
            return r;
        }
    });

    Object.defineProperty(Array.prototype, "getRandomElement", {
        value: function (): any[] {
            let lth = this.length - 0.1
            return this[Math.floor(Math.random() * lth)];
        }
    });

    Object.defineProperty(Array.prototype, "getRandomElements", {
        value: function (count: number): any[] {
            var shuffled = this.slice(0),
                i = this.length,
                min = i - count,
                temp, index
            while (i-- > min) {
                index = Math.floor((i + 1) * Math.random())
                temp = shuffled[index];
                shuffled[index] = shuffled[i];
                shuffled[i] = temp;
            }
            return shuffled.slice(min);
        }
    });

    Object.defineProperty(Array.prototype, "removeKey", {
        value: function (_key: string) {
            const temp = [];
            for (let key in this) {
                if (key == _key) continue;
                temp[key] = this[key];
            }
            return temp;
        }
    });

    Object.defineProperty(Array.prototype, "removeKeys", {
        value: function (keys: string[]) {
            const temp = [];
            for (let key in this) {
                if (keys.indexOf(key) != -1) continue;
                temp[key] = this[key];
            }
            return temp;
        }
    });

    Object.defineProperty(Array.prototype, "removeKeysBySelf", {
        value: function (keys: string[]) {
            for (let key in keys) {
                delete this[keys[key]];
            }
        }
    });

    Object.defineProperty(Array.prototype, "clear", {
        value: function () {
            this.splice(0, this.length);
        }
    });

    /** 
     * 扩展基础类 
     * 日期格式化 
     **/
    Date.prototype.format = function (pat: string = null): string {
        var year = this.getFullYear();
        var month = this.getMonth() + 1;
        var day = this.getDate();
        var hour = this.getHours();
        var minute = this.getMinutes();
        var second = this.getSeconds();
        var millisecond = this.getTime();
        // 两位补齐  
        month = month > 9 ? month : "0" + month;
        day = day > 9 ? day : "0" + day;
        hour = hour > 9 ? hour : "0" + hour;
        minute = minute > 9 ? minute : "0" + minute;
        second = second > 9 ? second : "0" + second;
        if (!pat) {
            pat = "yyyy-MM-dd";
        }
        pat = pat.replace(/yyyy/g, year);
        pat = pat.replace(/MM/g, month);
        pat = pat.replace(/dd/g, day);
        pat = pat.replace(/HH/gi, hour);
        pat = pat.replace(/mm/g, minute);
        pat = pat.replace(/ss/g, second);
        return pat;
    }

    // 日期相差天数  
    Date.prototype.diffday = function (date: number) {
        return Math.ceil((this.getTime() - date) / (1000 * 60 * 60 * 24));
    }

    // 日期加计算
    Date.prototype.add = function (days: number) {
        return new Date(this.getTime() + days * (1000 * 60 * 60 * 24));
    }

    // 日期减计算  
    Date.prototype.subtract = function (days: number) {
        return new Date(this.getTime() - days * (1000 * 60 * 60 * 24));
    }
    
    // Debug: 打印Node路径
    // @ts-ignore
    cc.Node.prototype.getPath = function () {
        let path = this.name;
        let parent = this.parent;
        while (parent) {
            path = parent.name + "/" + path;
            parent = parent.parent;
        }
        console.log(path);
        return path; 
    }
    let old_onTouchMoved = cc.ScrollView.prototype._onTouchMoved;
    cc.ScrollView.prototype._onTouchMoved = function(...arg){
        !this.isCancelTouchMove && this.enabled && old_onTouchMoved.apply(this, arg);
    }

    // 监听成员变量修改位置
    window["DebugSet"] = function (obj: object, attrName: string, func?: (v: any) => void){
        let tempKey = "__" + attrName;
        if(obj[tempKey] != null){
            console.error('属性重复定义:',attrName)
            return;
        }
        obj[tempKey] = obj[attrName];
        cc.js.getset(obj,attrName,(v)=>{
            return obj[tempKey];
        },(v)=>{
            console.warn('属性被修改:',attrName,v);
            obj[tempKey] = v;
            func && func(v);
        })
    }
    
    window["DebugGet"] = function (obj: object, attrName: string) {
        let tempKey = "__" + attrName;
        obj[tempKey] = obj[attrName];
        cc.js.set(obj,attrName,(v)=>{
            console.warn('属性被读取:',attrName,v);
            return obj[tempKey];
        })
    }

    // Debug: 打印调用栈
    const _error = new Error();
    window["getStackTrace"] = function () {
        /** @ts-ignore */
        Error.captureStackTrace ? Error.captureStackTrace(_error, window["getStackTrace"]) : _error.stack = (new Error()).stack;
        return _error.stack;
    }

    // Debug: 打印 Node destroy 位置
    // @ts-ignore
    // let oldDestroy = cc.Node.prototype.destroy
    // cc.Node.prototype.destroy = function () {
    //     console.warn("节点被destroy: " + this.getPath());
    //     return oldDestroy.call(this);
    // }
}
