export class CustomLoader extends fgui.GLoader
  {

    public is_texture : boolean;
    // public my_url : string;

    protected loadExternal()
    {
        /*
        开始外部载入，地址在url属性
        载入完成后调用OnExternalLoadSuccess
        载入失败调用OnExternalLoadFailed

        注意：如果是外部载入，在载入结束后，调用OnExternalLoadSuccess或OnExternalLoadFailed前，
        比较严谨的做法是先检查url属性是否已经和这个载入的内容不相符。
        如果不相符，表示loader已经被修改了。
        这种情况下应该放弃调用OnExternalLoadSuccess或OnExternalLoadFailed。
        */
        var _this = this;
        var url = this.url;
        var callback = function (err, asset) {
        if (_this.url != url || !cc.isValid(_this._node))
            // 已经改变了URL
            return;
        if (err)
            console.warn(err);
        if (asset instanceof cc.SpriteFrame){
            _this.is_texture = false;
            asset.addRef();
            _this.onExternalLoadSuccess(asset);
        } else if (asset instanceof cc.Texture2D){
            _this.is_texture = true;
            asset.addRef();
            let _res = new cc.SpriteFrame(asset);                
            _this.onExternalLoadSuccess(_res);
        }
        };        
        if (fgui.ToolSet.startsWith(url, "http://")
            || fgui.ToolSet.startsWith(url, "https://")){
            // || fgui.ToolSet.startsWith(url, '/'))            
            cc.assetManager.loadRemote(url, callback);
        }else{
            // if(fgui.ToolSet.startsWith(url , "icon/")){
            //     if(url.search(/(card|enemy|equip|fashion|gem|item)/) != -1){
            //         this.my_url = url;
            //         // console.error("loadExternal" , this.my_url);
            //     }                
            // }
            super.loadExternal();
            
        }
    }

    protected freeExternal(texture : cc.SpriteFrame)
    {
        //释放外部载入的资源        
        let _url = this.url;
        if (fgui.ToolSet.startsWith(_url, "http://")
            || fgui.ToolSet.startsWith(_url, "https://")
            /*|| fgui.ToolSet.startsWith(_url, '/')*/){
            if(this.is_texture){
                texture.getTexture().decRef();
                if(texture.getTexture().refCount <= 0){
                    cc.assetManager.releaseAsset(texture.getTexture());
                }
            }else{
                texture.decRef();
                if(texture.refCount <= 0){
                    cc.assetManager.releaseAsset(texture);
                }
            }            
        }
        
        // if(fgui.ToolSet.startsWith(_url , "UIBg")){
        //     // console.error("释放" , _url);
        //     // 删掉大图
        //     cc.resources.release(_url , cc.Texture2D);
        // }
        // if(this.my_url && this.my_url != ""){
        //     // console.error("释放" , this.my_url);
        //     cc.resources.release(this.my_url);
        //     this.my_url = null;        
        // }
        
        super.freeExternal(texture);
    }
  }