import { BasicGameManger } from './BasicGameManger';
import { LogicBlock } from '../LogicBlock/LogicBlock';
import { GameViewEvent, LevelConfig, LogicItem, PageItem, SelectNodePrefix } from '../GameAttribute';
import Timer from '../../Tools/Timer';
import Singleton from '../../singleton/Singleton';
import { GmManger } from '../../System/GmManger';
import GameNdrgView from '../../game/ui/GameNdrgView';

/** 脑洞热梗 游戏管理器 */
export class NdrgGameManger extends BasicGameManger {
    protected game_view: GameNdrgView;
    private currentPageIndex: number = 0;
    private pageView: cc.PageView = null;
    private bgNode: cc.Sprite = null;
    private selectList: cc.ScrollView = null;
    private selectItem: cc.Node = null;
    private collectedItems: {sl_item: string}[] = [];
    private finishPages: boolean[] = [];

    constructor() {
        super();
    }

    onLoadConfig(){
        this.game_view.Title = '匹配正确的发型'//this.lv_config.name;
        this.timeout = this.lv_config.timeout;
        this.game_view.setGoodsCount(this.lv_config.goodsCount);
        this.game_view.setHintDate(this.lv_config.hint);
        this.startTime = Date.now();
        this.updateLabelStatus(0);
        this.initPageSystem();
        this.updateNodeKeys(this.game_node);
        this.initLogicBlock();

        this.switchToPage(0, 0);
        this.setErrCount(GmManger.inst.hp999Value ? 999 : this.lv_config.errCount || 3);
        this.resume();
    }

    // 完成当前页面，切换到下一个页面
    private nextPage(curIndex: number){ 
        for(let i = curIndex + 1; i < this.finishPages.length; i++){
            if(!this.finishPages[i]){
                this.switchToPage(i);
                return;
            }
        }
    }

    // 启动业务逻辑判断流程
    private initLogicBlock(){
        console.log("onLoadConfig 开始跑逻辑", this.lv_config);
        this.lv_config.pageCfg && this.lv_config.pageCfg.pages.forEach((pageConfig, index) => {
            this.finishPages[index] = false;
            new LogicBlock({mode:'', cmds: pageConfig.select}, ()=>{
                console.log("pageConfig.select 完成", pageConfig.finish);
                this.finishPages[index] = true;
                if(pageConfig.complete){
                    new LogicBlock({mode:'', cmds: Array.isArray(pageConfig.complete) ? pageConfig.complete : ['!seq', pageConfig.complete]}, ()=>{
                        console.log("pageConfig.complete 完成", pageConfig.finish);
                        Timer.once(200, this, ()=> this.nextPage(index)); 
                        this.checkAllPagesFinished();
                    });
                }else{
                    Timer.once(200, this, ()=> this.nextPage(index)); 
                    this.checkAllPagesFinished();
                }
            });
        });

        let cmds: any[] = ['!seq', ...this.lv_config.rule];
        this.lv_config.cmds && cmds.push(this.lv_config.cmds);
        new LogicBlock({mode:'', cmds: cmds}, ()=>{
            console.warn("游戏所有流程已跑完");
        });

    }

    private initPageSystem(){
        if(!this.lv_config.pageCfg){
            return;
        }

        const pageNodeName = this.lv_config.pageCfg.pageNode;
        const bgNodeName = this.lv_config.pageCfg.bgNode;

        const pageNode = this.game_node.getChildByName(pageNodeName);
        if(pageNode){
            this.pageView = pageNode.getComponent(cc.PageView);
            if(!this.pageView){
                console.warn("PageView component not found on node:", pageNodeName);
            }
            pageNode.getChildByName('_view').getComponent(cc.Mask).enabled = true;
        }

        this.bgNode = this.game_node.getChildByName(bgNodeName)?.getComponent(cc.Sprite);
        if(!this.bgNode){
            console.warn("Background node not found:", bgNodeName);
        }

        this.selectList = this.game_node.getChildByName('selectList')?.getComponent(cc.ScrollView);
        if(this.selectList){
            this.selectItem = this.selectList.node.getChildByName('selectItem');
            if(this.selectItem){
                this.selectItem.active = false;
            }
            
            // 屏幕点击效果
            this.selectList.node.on(cc.Node.EventType.TOUCH_START,(event: cc.Event.EventTouch)=>{
                // this.clickEff.resetSystem();
                // this.clickEff.node.setPosition(this.clickEff.node.parent.convertToNodeSpaceAR( event.getLocation()));
                Singleton.SoundSystem.PlaySound("resources", "sound/click")
            })

        }

        if(this.pageView){
            this.pageView.node.on("scroll-ended", this.onPageChanged, this);
        }

        this.collectAndDisplayItems();
    }

    private switchToPage(index: number, duration: number = 0.35){
        if(!this.lv_config.pageCfg || !this.lv_config.pageCfg.pages){
            return;
        }

        const pages = this.lv_config.pageCfg.pages;
        if(index < 0 || index >= pages.length){
            return;
        }

        this.currentPageIndex = index;
        const pageConfig = pages[index];

        this.switchBackground(pageConfig.bg);
        this.executeEnterCommand(pageConfig);

        if(this.pageView){
            this.pageView.scrollToPage(index, duration);
        }

        this.game_view.rightBtn.active = true;
        this.game_view.leftBtn.active = true;
    }

    private onPageChanged(){
        const newIndex = this.pageView.getCurrentPageIndex();
        if(newIndex !== this.currentPageIndex){
            this.switchToPage(newIndex, 0);
        }
    }

    private switchBackground(bgPath: string){
        if(!this.bgNode || !bgPath){
            return;
        }

        this.loadRes(bgPath, cc.SpriteFrame, (spriteFrame: cc.SpriteFrame)=>{
            if(spriteFrame){
                this.bgNode.spriteFrame = spriteFrame;
            }else{
                console.warn("Failed to load background:", bgPath);
            }
        });
    }

    private executeEnterCommand(pageConfig: PageItem){
        if(!pageConfig.enter){
            return;
        }

        new LogicBlock({mode:'', cmds: Array.isArray(pageConfig.enter) ? pageConfig.enter : ['!seq', pageConfig.enter]});
    }

    private collectAndDisplayItems(){
        this.clearSelectList();
        this.collectedItems = [];

        
        this.lv_config.pageCfg.pages.forEach((pageConfig) => {
            const select = pageConfig.select;
            if(select){
                for(let i = 0; i < select.length; i++){
                    const item = select[i] as LogicItem;
                    if(item && typeof item === 'object' && item.mode === 'page' && item.sl_item){
                        this.collectedItems.push({
                            sl_item: item.sl_item,
                        });
                    }
                }
            }
        });

        for(let i = this.collectedItems.length - 1; i > 0; i--){
            const j = Math.floor(Math.random() * (i + 1));
            const temp = this.collectedItems[i];
            this.collectedItems[i] = this.collectedItems[j];
            this.collectedItems[j] = temp;
        }
        this.displayItems();
    }

    private displayItems(){
        if(!this.selectList || !this.selectItem){
            console.warn("Select list or select item not found.");
            return;
        }

        for(let i = 0; i < this.collectedItems.length; i++){
            const item = this.collectedItems[i];
            const itemNode = cc.instantiate(this.selectItem);
            const iconNode = itemNode.getChildByName('_icon');
            itemNode.active = true;
            itemNode.parent = this.selectList.content;
            // 为每个节点添加唯一的名称，用于后续操作
            itemNode.name = SelectNodePrefix + item.sl_item;

            this.loadRes(`selectImg/${item.sl_item}`, cc.SpriteFrame, (spriteFrame: cc.SpriteFrame)=>{
                const sprite = iconNode.getComponent(cc.Sprite);
                if(sprite && spriteFrame){
                    sprite.spriteFrame = spriteFrame;
                }else{
                    console.warn("Failed to load icon:", item.sl_item);
                }
            });
        }
    }

    private clearSelectList(){
        if(!this.selectList){
            return;
        }

        const children = this.selectList.content.children;
        for(let i = children.length - 1; i >= 0; i--){
            children[i].destroy();
        }
    }

    
	onDragFail(pos: cc.Vec2, config: LogicItem){
        const selectBB = this.selectList.node.getBoundingBoxToWorld();
		if(pos.y > selectBB.y + selectBB.height){
			this.setErrCount(this.errCount - 1);
            this.game_view.playErrEffect(pos);
            Singleton.SoundSystem.PlaySound("resources", "sound/err");
		}
	}

    onViewEvent(event: GameViewEvent){
        if(!this.lv_config.pageCfg || !this.lv_config.pageCfg.pages){
            return;
        }
        const pageCount = this.lv_config.pageCfg.pages.length;
        let duration = 0.35;
        if(event === GameViewEvent.RightPage){
            let nextIndex = this.currentPageIndex + 1;
            if(nextIndex >= pageCount){
                nextIndex = 0;
                duration = 0;
            }
            this.switchToPage(nextIndex, duration);
        }else if(event === GameViewEvent.LeftPage){
            let prevIndex = this.currentPageIndex - 1;
            if(prevIndex < 0){
                prevIndex = pageCount - 1;
                duration = 0;
            }
            this.switchToPage(prevIndex, duration);
        }
    }

    private checkAllPagesFinished(){
        if(this.finishPages.every((finished) => finished)){
            this.onGameOver(true);
        }
    }
}
