export class AndroidHelper {

    private static resolve_func : Function;
    private static reject_func : Function;

    /** 唤醒支付 */
    public static ToAliPay(info : string){
        if(!CC_JSB) return;
        let _data = info;
        jsb.reflection.callStaticMethod("org/cocos2dx/javascript/AppActivity" , "ToAliPay" , "(Ljava/lang/String;)V" , _data);
        return new Promise((r,j)=>{
            this.resolve_func = r;
            this.reject_func = j;
        });
    }

    /** 复制信息到剪切板 */
    public static CopyClipBoard(info : string){
        if(!CC_JSB) return;
        jsb.reflection.callStaticMethod("org/cocos2dx/javascript/AppActivity" , "CopyClipBoard" , "(Ljava/lang/String;)V" , info);
    }

    /** 是否安装了微信应用 */
    public static IsWeChatAvilible() : boolean {
        if(!CC_JSB) return;
        return jsb.reflection.callStaticMethod("org/cocos2dx/javascript/AppActivity" , "IsWeChatAvilible" , "()Z");
    }

    /** 是否安装了支付宝应用 */
    public static IsAliPayAvilible() : boolean {
        if(!CC_JSB) return;
        return jsb.reflection.callStaticMethod("org/cocos2dx/javascript/AppActivity" , "IsAliPayAvilible" , "()Z");
    }

    /** 跳转到微信 */
    public static JumpToWeChat(){
        if(!CC_JSB) return;
        jsb.reflection.callStaticMethod("org/cocos2dx/javascript/AppActivity" , "JumpToWeChat" , "()V");
    }

    /** 长震动 */
    public static VibrateLong(){
        if(!CC_JSB) return;
        jsb.reflection.callStaticMethod("org/cocos2dx/javascript/AppActivity" , "ToVibrate" , "(I)V" , 400);
    }

    /** 短震动 */
    public static VibrateShort(){
        if(!CC_JSB) return;
        jsb.reflection.callStaticMethod("org/cocos2dx/javascript/AppActivity" , "ToVibrate" , "(I)V" , 15);
    }

    /** 提示框 */
    public static ShowToast(info : string){
        if(!CC_JSB) return;
        jsb.reflection.callStaticMethod("org/cocos2dx/javascript/AppActivity" , "ShowToast" , "(Ljava/lang/String;)V" , info);
    }

    /** 支付回调 */
    public static AliPayCallBack(info : any , status : string){
        if(!CC_JSB) return;
        if(status == "9000"){
            // 成功
            this.resolve_func && this.resolve_func(info.alipay_trade_app_pay_response);
        }else{
            // 失败
            this.reject_func && this.reject_func(null);
        }
    }

    /** 授权回调(按理用不着) */
    public static AliAuthCallBack(info : string , status : string){
        if(!CC_JSB) return;
        console.log("Cocos2dxJavascriptJavaBridge AliAuthCallBack" , info , status);
    }
}

if(CC_JSB){
    globalThis["AndroidHelper"] = AndroidHelper;
}