import StorageSystem, { IStorageControler } from "./StorageSystem";

export default abstract class BaseStorageValue<T> implements IStorageControler {

    protected change : boolean;
    protected key : string;
    protected value : T;
    private monitor : boolean;
    public get Monitor(){
        return this.monitor;
    }

    public constructor(key : string , value : T , monitor : boolean = true){
        this.key = key;
        this.value = value;
        this.monitor = monitor;
        this.change = true;
        StorageSystem.Init.AddData(key , this);
    }

    abstract Save(_force : boolean) : any;
    abstract Load(value : any);
    abstract get GetValue() : T;
    abstract set SetValue(value : T);
}