export class IOSHelper {

    private static resolve_func : Function;
    private static reject_func : Function;

    /** 唤醒支付 */
    public static IOSToAliPay(info : string){
        if(!CC_JSB) return;
        let _data = info;
        jsb.reflection.callStaticMethod("SDKWrapper" , "ToAliPay:" , info);
        return new Promise((r,j)=>{
            this.resolve_func = r;
            this.reject_func = j;
        });
    }

    public static IOSCopyClipBoard(info : string){
        if(!CC_JSB) return;
        jsb.reflection.callStaticMethod("SDKWrapper" , "CopyClipBoard:" , info);
    }

    /** 是否安装了微信应用 */
    public static IOSIsWeChatAvilible() : boolean {
        if(!CC_JSB) return;
        return jsb.reflection.callStaticMethod("SDKWrapper" , "isAppInstalled:" , "weixin://");
    }

    /** 是否安装了支付宝应用 */
    public static IOSIsAliPayAvilible() : boolean {
        if(!CC_JSB) return;
        return jsb.reflection.callStaticMethod("SDKWrapper" , "isAppInstalled:" , "alipay://");
    }

    /** 跳转到微信 */
    public static IOSJumpToWeChat(){
        if(!CC_JSB) return;
        jsb.reflection.callStaticMethod("SDKWrapper" , "OpenApp:" , "weixin://");
    }

    /** 提示 */
    public static ShowToast(info : string){
        if(!CC_JSB) return;
        jsb.reflection.callStaticMethod("SDKWrapper" , "ShowMessage:" , info);
    }

    /** 长震动 */
    public static VibrateLong(){
        if(!CC_JSB) return;
        // @ts-ignore
        jsb.reflection.callStaticMethod("SDKWrapper" , "ToVibrateHeavy");
    }


    /** 短震动 */
    public static VibrateShort(){
        if(!CC_JSB) return;
        // @ts-ignore
        jsb.reflection.callStaticMethod("SDKWrapper" , "ToVibrateMedium");
    }

    /** 支付回调 */
    public static IOSAliPayCallBack(info : any , status : string){
        if(!CC_JSB) return;
        console.log("Cocos2dxJavascriptJavaBridge AliPayCallBack" , JSON.stringify(info)  , status);
        if(status == "9000"){
            // 成功
            this.resolve_func && this.resolve_func(info.alipay_trade_app_pay_response);
        }else{
            // 失败
            this.reject_func && this.reject_func(null);
        }
    }
}

if(CC_JSB){
    globalThis["IOSHelper"] = IOSHelper;
}