
import ViewBase from "../../engine/ViewBase";
import {GmManger} from "../../System/GmManger";
import { ViewConfig } from "../../System/ui/UI_Config";
import UIManager from "../../System/ui/UIManager";

const {ccclass, property} = cc._decorator;

@ccclass
export default class GmView extends ViewBase {

	@property({ type: cc.Sprite, displayName:'关闭按钮' })
	closeBtn: cc.Sprite = null;

	@property({ type: cc.Toggle, displayName:'自动重开' })
	restartToggle: cc.Toggle = null;

	@property({ type: cc.Toggle, displayName:'免倒计时' })
	timeToggle: cc.Toggle = null;

	@property({ type: cc.Toggle, displayName:'血量999' })
	hpToggle: cc.Toggle = null;

	@property({ type: cc.Toggle, displayName:'自动下一页' })
	pageToggle: cc.Toggle = null;

	@property({ type: cc.EditBox, displayName:'下一页延迟' })
	pageEditBox: cc.EditBox = null;

	@property({ type: cc.Toggle, displayName:'物品不随机' })
	itemRandomToggle: cc.Toggle = null;

	@property({ type: cc.Toggle, displayName:'显示角色ID' })
	roleIdTiggle: cc.Toggle = null;

	@property({ type: cc.Toggle, displayName:'打开边界检测' })
	openBorderToggle: cc.Toggle = null;

	@property({ type: cc.EditBox, displayName:'边界检测时间' })
	openBorderEditBox: cc.EditBox = null;

	@property({ type: cc.Button, displayName:'关卡顺序按钮' })
	lvOrderBtn: cc.Button = null;

    start () {
		this.onAddEvent(this.closeBtn.node,()=>{
			this.closeView();
		})
    }

	onInitChild(level?: number){
		this.onOpen();
	}

	private onOpen() {
		this.restartToggle.isChecked = GmManger.inst.overRestartValue;
		this.timeToggle.isChecked = GmManger.inst.freeTimeValue;
		this.hpToggle.isChecked = GmManger.inst.hp999Value;
		this.pageToggle.isChecked = GmManger.inst.autoNextPageValue;
		this.pageEditBox.string = GmManger.inst.autoNextPageDelayValue.toString();
		this.itemRandomToggle.isChecked = GmManger.inst.itemNotRandomValue;
		this.roleIdTiggle.isChecked = GmManger.inst.showRoleIdValue == 1;
		this.openBorderToggle.isChecked = GmManger.inst.openBorderValue == 1;
		this.openBorderEditBox.string = GmManger.inst.openBorderToggleTimeValue.toString();
		this.openBorderEditBox.node.active = this.openBorderToggle.isChecked;

		this.onAddToggleEvent(this.restartToggle, () => this.onRestartToggle());
		this.onAddToggleEvent(this.timeToggle, () => this.onTimeToggle());
		this.onAddToggleEvent(this.hpToggle, () => this.onHpToggle());
		this.onAddToggleEvent(this.pageToggle, () => this.onPageToggle());
		this.onAddEditBoxEvent(this.pageEditBox, () => this.onPageEditBox());
		this.onAddToggleEvent(this.itemRandomToggle, () => this.onItemRandomToggle());
		this.onAddToggleEvent(this.roleIdTiggle, () => this.onRoleIdToggle());
		this.onAddToggleEvent(this.openBorderToggle, () => this.onOpenBorderToggle());
		this.onAddEditBoxEvent(this.openBorderEditBox, () => this.onOpenBorderEditBox());
		this.onAddEvent(this.lvOrderBtn.node, () => this.onLvOrderBtn());
	}

	private onAddToggleEvent(toggle: cc.Toggle, handler: Function) {
		if(toggle && toggle.node) {
			toggle.node.on('toggle', handler, this);
		}
	}

	private onAddEditBoxEvent(editBox: cc.EditBox, handler: Function) {
		if(editBox && editBox.node) {
			editBox.node.on('editing-return', handler, this);
		}
	}

	private onRestartToggle() {
		GmManger.inst.setOverRestart(this.restartToggle.isChecked);
	}

	private onTimeToggle() {
		GmManger.inst.setFreeTime(this.timeToggle.isChecked);
	}

	private onHpToggle() {
		GmManger.inst.setHp999(this.hpToggle.isChecked);
	}

	private onPageToggle() {
		GmManger.inst.setAutoNextPage(this.pageToggle.isChecked);
	}

	private onPageEditBox() {
		if(this.pageEditBox.string) {
			let delay = Number(this.pageEditBox.string);
			if(delay <= 0) {
				delay = 1;
			}
			GmManger.inst.setAutoNextPageDelay(delay);
		} else {
			this.pageEditBox.string = "1";
			GmManger.inst.setAutoNextPageDelay(1);
		}
	}

	private onItemRandomToggle() {
		GmManger.inst.setItemNotRandom(this.itemRandomToggle.isChecked);
	}

	private onRoleIdToggle() {
		GmManger.inst.setShowRoleId(this.roleIdTiggle.isChecked ? 1 : 0);
	}

	private onOpenBorderToggle() {
		GmManger.inst.setOpenBorder(this.openBorderToggle.isChecked ? 1 : 0);
		this.openBorderEditBox.node.active = this.openBorderToggle.isChecked;
	}

	private onOpenBorderEditBox() {
		if(this.openBorderEditBox.string) {
			let time = Number(this.openBorderEditBox.string);
			if(time < 0) {
				time = 1;
			}
			GmManger.inst.setOpenBorderToggleTime(time);
		} else {
			this.openBorderEditBox.string = "1";
			GmManger.inst.setOpenBorderToggleTime(1);
		}
	}

	private onLvOrderBtn() {
		UIManager.instance.showView(ViewConfig.GmLvOrderView, () => {
			this.closeView(true);
		});
	}

	onDestroy() {
	}

}
