import ResourcesManager from "../engine/ResourceManager";
import { UI_Config, UI_Cache_Type } from "../System/ui/UI_Config";

const { ccclass, property } = cc._decorator;

@ccclass
export class GrayscaleGradientHelper {
    private static _effectAsset: cc.EffectAsset = null;
    private static _isLoaded: boolean = false;

    public static async loadEffect(): Promise<void> {
        if (this._isLoaded && this._effectAsset) return;
        
        return new Promise((resolve, reject) => {
            ResourcesManager.instance.loadResByBundleNameAndPaths("resources", "effects/grayscale_gradient", cc.EffectAsset, (effect: cc.EffectAsset) => {
                if (!effect) {
                    console.error('[GrayscaleGradientHelper] Load effect failed:', effect);
                    resolve();
                    return;
                }
                this._effectAsset = effect;
                this._isLoaded = true;
                resolve();
            });
        });
    }

    public static async applyToSprite(sprite: cc.Sprite, progress: number): Promise<void> {
        if (!sprite || !sprite.node) return;

        await this.loadEffect();

        const clampedProgress = Math.max(0, Math.min(1, progress));

        if (this._effectAsset) {
            let material = cc.Material.create(this._effectAsset);
            let materialVariant = cc.MaterialVariant.create(material, sprite);
            materialVariant.setProperty('progress', clampedProgress);
            sprite.setMaterial(0, materialVariant);
        } else {
            console.warn('[GrayscaleGradientHelper] Effect not loaded, effect may not display correctly');
        }
    }

    public static async applyToNode(node: cc.Node, progress: number): Promise<void> {
        if (!node) return;

        const sprites = node.getComponentsInChildren(cc.Sprite);
        for (const sprite of sprites) {
            await this.applyToSprite(sprite, progress);
        }
    }

    public static clearEffect(sprite: cc.Sprite): void {
        if (!sprite) return;
        sprite.setMaterial(0, null);
    }

    public static clearNodeEffect(node: cc.Node): void {
        if (!node) return;
        const sprites = node.getComponentsInChildren(cc.Sprite);
        for (const sprite of sprites) {
            this.clearEffect(sprite);
        }
    }

    public static async animateProgress(sprite: cc.Sprite, fromProgress: number, toProgress: number, duration: number, onComplete?: () => void): Promise<void> {
        if (!sprite || !sprite.node) {
            onComplete && onComplete();
            return;
        }

        await this.loadEffect();

        const startTime = Date.now();
        const startProgress = fromProgress;

        const update = () => {
            const elapsed = Date.now() - startTime;
            const t = Math.min(elapsed / (duration * 1000), 1);
            const easedT = this.easeOutQuad(t);
            const currentProgress = startProgress + (toProgress - startProgress) * easedT;

            this.applyToSprite(sprite, currentProgress);

            if (t < 1) {
                requestAnimationFrame(update);
            } else {
                onComplete && onComplete();
            }
        };

        update();
    }

    private static easeOutQuad(t: number): number {
        return t * (2 - t);
    }
}
