    public static InitFGUI() {
        ui_event = new EventManager;
        Logger.log("初始化FGUI")
        fgui.GRoot.create();
        fgui.UIObjectFactory.setLoaderExtension(CustomLoader);

        let _FGUI_Node = new cc.Node("FGUI");
        _FGUI_Node.parent = cc.director.getScene();
        _FGUI_Node.zIndex = 10000;
        _FGUI_Node.group = 'ui'
        let _widge = _FGUI_Node.addComponent<cc.Widget>(cc.Widget);
        _widge.alignMode = cc.Widget.AlignMode.ALWAYS;
        _widge.isAlignLeft = _widge.isAlignBottom = true;
        _widge.left = _widge.bottom = 0;
        cc.game.addPersistRootNode(_FGUI_Node);
        fgui.GRoot.inst.node.parent = _FGUI_Node;
        // 根节点取消吞噬触摸, 为了玩家能被点击
        fgui.GRoot.inst.inputProcessor && fgui.GRoot.inst.inputProcessor.setSwallowTouches(false);
        let visibleSize = cc.view.getVisibleSize();

        let w = visibleSize.width;
        let h = visibleSize.height;

        if (w / h < 16 / 9) {
            // IPAD类，走这段
            fgui.GRoot.inst.setSize(1560, 877);
            let scalex = w / 1560;
            let scaley = h / 877;
            if (scalex < scaley) {
                fgui.GRoot.inst.setScale(scalex, scalex);
            } else {
                fgui.GRoot.inst.setScale(scaley, scaley);
            }
            fgui.GRoot.inst.node.y = h / 2 + (877 / 2);
        }

        cc.resources.preload("fgui/CJDH_difa");
        cc.resources.load("json/NoAlphaUI", cc.JsonAsset, (err, res) => {
            this.AlphaUIName = res.json;
        });

        this.OnCanvasResize();
        
        GameEventSystem.on(FGUIEvent.UIEVENT_OPENVIEW, this, (key: string, ui: BaseUI)=>{
            ui.IsVaild && ui_event.dispatch(key, ui);
        });
    }

