    public static OnCanvasResize(){
        cc.view.on("canvas-resize" , SingletonAttribute.CheckIPadMode , SingletonAttribute);
    }

    public static OffCanvasResize(){
        cc.view.off("canvas-resize" , SingletonAttribute.CheckIPadMode , SingletonAttribute)
    }

    public static FixIPadFGUI() {
        if(!fgui.GRoot["_inst"]) return;
        let visibleSize = cc.view.getVisibleSize();

        let w = visibleSize.width;
        let h = visibleSize.height;

        // IPAD类，走这段
        fgui.GRoot.inst.setSize(1560, 877);
        let scalex = w / 1560;
        let scaley = h / 877;
        if (scalex < scaley) {
            fgui.GRoot.inst.setScale(scalex, scalex);
        } else {
            fgui.GRoot.inst.setScale(scaley, scaley);
        }
        fgui.GRoot.inst.node.y = h / 2 + (877 / 2);

        fgui.GRoot.inst.node.parent.parent = cc.director.getScene().getChildByName("Scene").getChildByName("Scene");
        // cc.game.addPersistRootNode(fgui.GRoot.inst.node.parent.parent);
        fgui.GRoot.inst.node.y = 877;
    }

    public static FixNormalFGUI(){
        if(!fgui.GRoot["_inst"]) return;
        fgui.GRoot.inst.node.parent.parent = cc.director.getScene();
        cc.game.addPersistRootNode(fgui.GRoot.inst.node.parent);
        fgui.GRoot.inst.node.y = 877;
    }
