    // 已存在界面
    private static readonly inited_ui: Map<string, BaseUI> = new Map<string, BaseUI>();
    public static GetInitUI<T extends BaseUI>(data: { tag: string, pkgname: string, resname: string }, _ui?: GameUIClass<T>, async: boolean = true, width: number = fgui.GRoot.inst.width, height: number = fgui.GRoot.inst.height): T {
        let key = data.tag + data.pkgname + data.resname;
        if (!FGUIManager.inited_ui.has(key)) {
            if(!_ui) return null;
            FGUIManager.inited_ui.set(key, new _ui(key, data.pkgname, data.resname, width, height, async));
        }else{

            let ui = FGUIManager.inited_ui.get(key) as T;
            if(!ui.IsVaild){
                DebugLogSystem.appErrorReport(`GetInitUI err:使用已释放的ui,key:${key}, IsVaild: ${ui.IsVaild},\n${getStackTrace()}`)
                FGUIManager.inited_ui.set(key, new _ui(key, data.pkgname, data.resname, width, height, async));
            }
        }
        return FGUIManager.inited_ui.get(key) as T;
    }

    public static HasUi(data: { tag: string, pkgname: string, resname: string }): boolean {
        let key = data.tag + data.pkgname + data.resname;
        return FGUIManager.inited_ui.has(key);
    }

    public static HasOpenUi(data: { tag: string, pkgname: string, resname: string }): boolean {
        let key = data.tag + data.pkgname + data.resname;
        return FGUIManager.inited_ui.has(key) && FGUIManager.inited_ui.get(key).Opening;
    }
    

    /** 删除界面(tag = data.tag + data.pkgname + data.resname) */
    public static DeleteUI<T extends BaseUI>(tag: string) {
        if (!FGUIManager.inited_ui.has(tag)) return;
        (FGUIManager.inited_ui.get(tag) as T).View?.dispose();
        FGUIManager.inited_ui.delete(tag);
    }

    public static CloseAllView(unclose_name_list: string[] = null) {
        for (let value of FGUIManager.inited_ui.values()) {
            if (unclose_name_list && unclose_name_list.includes(value.name)) continue;
            value.CloseView();
        }
    }

    public static CloseView(data: { tag: string, pkgname: string, resname: string }) {
        this.HasUi(data) && this.GetInitUI(data).CloseView();
    }

    public static CleanAllUI(unclean_name_list: string[] = null) {
        let _ui: BaseUI;
        for (let key of FGUIManager.inited_ui.keys()) {
            _ui = FGUIManager.inited_ui.get(key);
            if (unclean_name_list && unclean_name_list.includes(_ui.name)) continue;
            _ui.Opening && _ui.CloseView(); 
            _ui.Dispose();
            FGUIManager.inited_ui.delete(key);
        }
    }

    /** 最顶层UI */
    public static GetCurTopLayerUI() {
        if (fgui.GRoot.inst.numChildren == 0) return null;
        let _com = fgui.GRoot.inst.getChildAt(fgui.GRoot.inst.numChildren - 1);
        return { name: _com.packageItem.name, layer: fgui.GRoot.inst.numChildren - 1 };
    }

    public static AlphaUIName: string[];

    /** 没有透明度的最顶层UI */
    public static GetCurTopNoAlphaUI() {
        if (fgui.GRoot.inst.numChildren == 0) return null;
        if (this.AlphaUIName == null) {
            return this.GetCurTopLayerUI();
        }
        let _n;
        for (let i = fgui.GRoot.inst.numChildren - 1; i >= 0; i--) {
            if (!fgui.GRoot.inst.getChildAt(i).packageItem) continue;
            _n = fgui.GRoot.inst.getChildAt(i);
            if (this.AlphaUIName.includes(_n.packageItem.name)) {
                return { name: _n.packageItem.name, layer: i };
            }
        }
        return null;
    }


    /**改图片颜色 */
    public static SetImageColor(img: fairygui.GObject, color: number) {
        let spliceColor = (color) => {
            let result = { r: -1, g: -1, b: -1 };
            result.b = color % 256;
            result.g = Math.floor((color / 256)) % 256;
            result.r = Math.floor((color / 256) / 256);
            return result;
        }
        let result = spliceColor(color);

        let cc_color = new cc.Color(result.r, result.g, result.b);

        img.node.color = cc_color;
        img["color"] && (img["color"] = cc_color);

        spliceColor = null;
    }

    /**
     * 时间转字符串
     * @param time 
     * @param out_hour 
     * @param out_min 
     * @param out_sec 
     */
    public static TimeToString(time: number): string {

        const hour: number = Math.floor(time / 1000 / 60 / 60);
        const min: number = Math.floor((time - hour * 60 * 60 * 1000) / 1000 / 60);
        const sec: number = Math.floor((time - hour * 60 * 60 * 1000 - min * 60 * 1000) / 1000);
        return hour + ":" + (Array(2).join('0') + min).slice(-2) + ":" + (Array(2).join('0') + sec).slice(-2);
    }


