    public static SecondToString(second: number): string {
        const h = Math.floor(second / 3600);
        const m = Math.floor(second / 60) % 60;
        const s = Math.floor(second % 60);
        return (h > 9 ? "" : "0") + h + ":" + (m > 9 ? "" : "0") + m + ":" + (s > 9 ? "" : "0") + s;
    }

