    public static AsyncCreateView(info: { tag: string, pkgname: string, resname: string }, closeBtn: string = "btn_sure") {
        let handler = new fgui.AsyncOperation();
        handler.createObject(info.pkgname, info.resname);
        handler.callback = (obj: fgui.GObject) => {
            let view = obj.asCom;
            fgui.GRoot.inst.addChild(view);
            view.setSize(fgui.GRoot.inst.width,fgui.GRoot.inst.height);
            view.getChild(closeBtn).onClick(() => {
                view.dispose();
            })
        }
    }

    
