/** 通过路径获得node */
function GetChildByPath(gcom: fairygui.GComponent, paths: string[]) {
    var obj;
    for (var i = 0; i < paths.length; ++i) {
        if ( !(obj = gcom.getChild(paths[i])) ) break;
        gcom = obj;
    }
    return obj;
}

/**
 * 属性装饰器: 快速获取fgui node
 * 使用示例: 
 * class StartView ... {
 *  @GetUi('bg_14/text_server_name') label: fairygui.GLabel;
 *  ...
 * }
 * 
 * 以上代码等效于:
 * class StartView ... {
 *  get label(){
 *      return this['_ui$label'] = this['_ui$label'] || (this.view || this.component).getChildByPath(path)
 * }
 * 
 * 注: fgui类必须有 this.view 或 this.component 成员变量才能使用该装饰器
 * 
 * @param path 节点路径, path == '' 时获取的是根节点 this.view
 * @param isController 是否获取控制器对象
 * @param controllerName 控制器对象名
 */
export function GetUi(path: string, isController: boolean = false, controllerName?: string): any {

    /** class new实例时执行一下函数 */
    function normalized (fguiObj: { view?: fairygui.GComponent, component?: fairygui.GComponent }, propName: string) {
        let _propName = (isController ? '_ui$' : '_con$') + propName;
        let paths = path.split('/');
        let strlen = path.length;
        cc.js.getset(fguiObj, propName, function(v){
            // this是class实例

            /** 第一次获取时跑 GetChildByPath 并缓存到 this[_propName]*/
            if(this[_propName] == null){
                let view: fairygui.GComponent = this.view || this.component;
                CC_DEBUG && !view && console.error("GetUi 找不到fgui界面的 view || component 变量")

                /** strlen == 0 表示根节点 this.view */
                let tempObj = strlen == 0 ? view : GetChildByPath(view, paths);
                this[_propName] = isController && tempObj ? tempObj.getController(controllerName) : tempObj;
                CC_DEBUG && !this[_propName] && console.error("GetUi 找不到fgui界面的 node", paths)
            }
            return this[_propName] 

        },function(curr_v: any){
            this[_propName] = curr_v;
            return this[_propName] 
        })
    }
    return normalized;
}

/**
 * 属性装饰器: 快速获取 fairygui.Controller
 * 使用示例: 
 * class StartView ... {
 *  @GetUi('','c1') c1: fairygui.Controller;
 *  ...
 * }
 */
export function GetCon(path: string, controllerName: string): any {
    return GetUi(path, true, controllerName);
}

/**
 * 属性装饰器: 绑定fgui node按钮事件
 * 使用示例: 
 * class StartView ... {
 *  @UIBtn('btn_start')
 *  protected myClickFunc(){}
 *  ...
 * }
 * 
 * 以上代码等效于:
 * class StartView ... {
 *  Init(){
 *     super.Init()
 *     this["_btn$myClickFunc"] && this["_btn$myClickFunc"].Dispose()
 *     let view: fairygui.GComponent = this.view || this.component;
 *     let tempObj: fairygui.GComponent = path == '' ? view : GetChildByPath(view, path.split('/'));
 *     tempObj && ( this["_btn$myClickFunc"] = new FguiButton(tempObj.name, tempObj.parent, this.myClickFunc.bind(this, args)) );
 *  }
 *  ...
 * }
 * 
 * 注: fgui类必须有 this.view 或 this.component 成员变量以及有 this.Init 函数才能使用该装饰器 
 * 
 * @param path 控制器所在node路径, path == '' 时获取的是根节点 this.view
 * @param controllerName 控制器对象名
*/
export function UIBtn(path: string, args?: any){
    // if(path == ''){
    //     console.error("@UIBtn path 参数不能为空", path);
    //     return;
    // }

    /** class new实例时执行一下函数 */
    function normalized (fguiObj: object, propName: string) {
        
        let oldInit: Function = fguiObj['Init'];
        if(!oldInit){
            console.error("@UIBtn 找不到Init函数无法绑定fgui buttion事件", path, propName, fguiObj.constructor.name);
            return;
        }
        let oldDispose = fguiObj['Dispose'];
        if(oldDispose){           
            if (!fguiObj['ClearBtnEvents']) {
                fguiObj['Dispose'] = function() {
                    let _btnarr : FguiButton[] = this['_btnComArr'];  
                    oldDispose.call(this);                    
                    for (let i = 0, len = _btnarr.length; i < len; i++) {
                        _btnarr[i].Dispose();
                    }
                    _btnarr.length = 0;
                }
            }
        }

        fguiObj['Init'] = function(){

            let ret = oldInit.call(this, ...arguments);
            let view: fairygui.GComponent = this.view || this.component;
            if(!view){
                console.error("@UIBtn 找不到fgui界面的 view || component 变量", path, propName, this.constructor.name);
                return ret;
            }

            /** 先清除父类绑定的按钮事件 */
            let _propName = '_btn$' + propName;
            let fguiBtn: FguiButton = this[_propName];
            fguiBtn && fguiBtn.Dispose()

            /** 绑定按钮事件 */
            let clickFunc = this[propName];
            let tempObj: fairygui.GComponent = path == '' ? view : GetChildByPath(view, path.split('/'));
            if(tempObj){
                if(this.UIBtn){
                    this[_propName] = fguiBtn = this.UIBtn(tempObj.name, tempObj.parent, clickFunc, args);
                }else{
                    this[_propName] = fguiBtn = new FguiButton2(tempObj.name, tempObj.parent, clickFunc ,this, args);
                    this['_btnComArr'] = this['_btnComArr'] || [];
                    this['_btnComArr'].push(fguiBtn);
                }                
            }
            return ret;
        }
    };
    return normalized;
}

