    /**
     * 
     * @param dayOfWeek 目标星期
     * @param hour 小时
     * @param minute 分钟
     * @param second 秒数
     * @param nextWeek 
     * @returns 时间戳
     */
    public static getTimestampForDayAndTime(dayOfWeek, hour, minute = 0, second = 0, nextWeek = false) {
        const now = new Date();
        const currentDayOfWeek = now.getDay();  // 获取今天是星期几
        let daysUntilTargetDay = (dayOfWeek - currentDayOfWeek) % 7;  // 计算目标星期几与今天的天数差
        if(daysUntilTargetDay < 0 ){
            daysUntilTargetDay += 7;
        }

        // 设置到达目标星期几的时间
        now.setDate(now.getDate() + daysUntilTargetDay);
        now.setHours(hour, minute, second, 0);

        return now.getTime();  // 返回时间戳
    }


    public static formatTimestamp(timestamp: number) {
        const date = new Date(timestamp);

        const year = date.getFullYear();
        const month = (date.getMonth() + 1).toString().padStart(2, '0');  // 月份从0开始，需要加1；padStart用于补零
        const day = date.getDate().toString().padStart(2, '0');  // 补零

        const formattedDate = `${year}年${month}月${day}日`;
        return formattedDate;
    }


