    /** 微信游戏圈 */
    public CreateGameClubButton(left: number, top: number, width: number, height: number) {
        if (!this.api) return;
        return this.api.createGameClubButton({
            style: {
                left: left,
                top: top,
                width: width,
                height: height
            }
        });
    }

    /** 分包加载 */
    public LoadSubPackage(name: string, cbfunc: Function, cbprogress: Function, cbobj: any) {
        if (!this.api) return;
        let task = this.api.loadSubpackage({
            name: name,
            success: () => {
                cbfunc && cbfunc.call(cbobj);
                task.onProgressUpdate(null);
            }
        });
        task.onProgressUpdate(cbprogress.bind(cbobj));
    }

    public AddOnShowEventListener(callback: Function, thisobj: any) {
        this.onshow_fun.push({ callback: callback, thisobj: thisobj });
    }

    public RemoveShowEventListener(callback: Function, thisobj: any) {
        const removeshoweventlistener = (callback, thisobj) => {
            const item: { callback: Function, thisobj: any } = this.onshow_fun.filter(item => item.callback === callback && item.thisobj === thisobj)[0];
            const index = this.onshow_fun.indexOf(item, 0);
            if (index == -1) return;
            if (index == 0) { this.onshow_fun.shift(); return; }
            else if (index == this.onshow_fun.length - 1) { this.onshow_fun.pop(); return; }
            else {
                this.onshow_fun.splice(index, 1);
            }
        };
        removeshoweventlistener(callback, thisobj);
    }

    public AddOnHideEventListener(callback: Function, thisobj: any) {
        this.onhide_fun.push({ callback: callback, thisobj: thisobj });
    }

    public RemoveHideEventListener(callback: Function, thisobj: any) {
        const removehideeventlistener = (callback, thisobj) => {
            const item: { callback: Function, thisobj: any } = this.onhide_fun.filter(item => item.callback === callback && item.thisobj === thisobj)[0];
            const index = this.onhide_fun.indexOf(item, 0);
            if (index == -1) return;
            if (index == 0) { this.onhide_fun.shift(); return; }
            else if (index == this.onhide_fun.length - 1) { this.onhide_fun.pop(); return; }
            else {
                this.onhide_fun.splice(index, 1);
            }
        };
        removehideeventlistener(callback, thisobj);
    }

