import BasePlatformAPI from "./BasePlatformAPI";

export type ShareParam = {
    /** 转发内容类型 */
    channel? : null|"article"|"video"|"token"|"invite";
    /** 分享素材模板 id，指定通过平台审核的 templateId 来选择分享内容，需在平台设置且通过审核 */
    templateId? : string;
    /** 分享文案，不传则默认使用后台配置内容或平台默认。 */
    desc? : string;
    /** 转发标题，不传则默认使用后台配置或当前小游戏的名称。 */
    title? : string;
    /** 转发显示图片的链接，可以是网络图片路径或本地图片文件路径或相对代码包根目录的图片文件路径，显示图片长宽比推荐 5:4 */
    imageUrl? : string;
    /** 查询字符串，必须是 key1=val1&key2=val2 的格式。从这条转发消息进入后，可通过 tt.getLaunchOptionsSync 或 tt.onShow 获取启动参数中的 query。 */
    query? : string;
    /** 附加信息 */
    extra? : Extra;
    success? : Function;
    fail? : Function;
    complete? : Function;
}

export type Extra = {
    /** 是否支持跳转到播放页， 以及支持获取视频信息等接口 （为 true 时会在 success 回调中带上 videoId） */
    withVideoId : boolean;
    /** 视频地址 ，分享一个本地视频 */
    videoPath : string;
    /** 视频话题(仅抖音支持) ，目前由 hashtag_list 代替，为保证兼容性，建议同时填写两个。 */
    videoTopics : string[];
    /** 是否分享为挑战视频 ( 仅头条支持 ) */
    createChallenge? : boolean;
    /** 生成输入的默认文案 */
    video_title? : string;
    /** 视频话题(仅抖音支持) */
    hashtag_list : string[];
    /** 分享视频的标签，可以结合获取抖音视频排行榜使用 */
    videoTag? : string;
    /** 抖音 pgc 音乐的短链(仅抖音支持，需要基础库版本大于 1.90)  */
    defaultBgm? : string;
    /** 抖音上可用的剪映模板 ID */
    cutTemplateId? :string;
    /** 剪映模板不可用或者剪映模板 ID 无效的时候是否直接回调失败。 */
    abortWhenCutTemplateUnavailable? : boolean;
}

export default class ByteShareAPI extends BasePlatformAPI {

    private static byteshare : ByteShareAPI = null;
    public static get Init() : ByteShareAPI{
        if(this.byteshare == null){
            this.byteshare = new ByteShareAPI();
        }
        return this.byteshare;
    }

    /** 显示当前小游戏页面的转发按钮。转发按钮位于小游戏页面右上角的“更多”中。 */
    public ShowShareMenu(){
        if(!this.api) return;
        this.api.showShareMenu();
    }

    /** 隐藏转发按钮。 */
    public HideShareMenu(){
        if(!this.api) return;
        this.api.hideShareMenu();
    }

    /** 主动调用是指通过 tt.shareAppMessage 调起视频发布器，传入该方法的参数为 ShareParam 类型。 */
    public ShareMessage(_shareparam : ShareParam){
        if(!this.api) return;        
        return this.api.shareAppMessage(_shareparam);
    }

    /** 被动调用是指通过 tt.onShareAppMessage 监听用户点击分享的行为，然后在回调函数中返回一个ShareParam对象。 */
    public OnShareMessage(_handle : Function){
        if(!this.api) return;
        this.api.onShareAppMessage(_handle);
    }

    /** 跳转到分享的视频播放页面。 */
    public NavigateToVideoView(_video_id : string) : Promise<any>{
        if(!this.api) return;
        return this.api.navigateToVideoView({
            videoId : _video_id
        });
    }
}