import { GameMode } from "../../gamePlaySystem/GameAttribute";

export enum ShowCityNameType {
    MY = 0,
    NPC = 1,
    OTHER = 2
}

export interface UIDataInfo {
    tag: string,
    pkgname: string,
    resname: string
}

export default class UIData {
    public static readonly Page_Name = "Page";
    /** 加载 */
    public static readonly Page_Loading = { tag: "Page_Loading", pkgname: "Loading", resname: "page_loading" };
  

    static GetItemIconUrl(_url: string) {
        return _url.includes("ui://") ? _url : ("icon/item/" + _url.replace(".png", ""));//GameLoad.getRealResURL("ItemIcon", "res/ItemIcon/" + _url);
    }

    static GetFashionIconUrl(_url: string) {
        return "icon/fashion/" + _url.replace(".png", "");
    }

    static GetEquipIconUrl(_pkgname: string, _url: string) {
        return "icon/equip/" + _url.split("/")[2].replace(".png", "");
    }

    static GetCardIconUrl(_url: string) {
        return "icon/card/" + _url.replace(".png", "");
    }

    static GetGemIconUrl(_url: string) {
        return "icon/gem/" + _url.replace(".png", "");
    }

    static GetEnemyIconUrl(_url: string) {
        return "icon/enemy/" + _url.replace(".png", "");
    }

    static GetSystemIconUrl(_url: string) {
        return "icon/system/" + _url.replace(".png", "");
    }

    static GetBgUrl(_url: string) {
        let strs = _url.split("/");
        return "UIBg/" + strs[strs.length - 1];
    }

    static GetLvIcon(url: string, gameMode: GameMode){
        if(!url) return null;
        return "icon/" + gameMode + "/" + url;
    }

    
    static GetGameModeIcon(url: string){
        if(!url) return null;
        return "icon/modes/" + url;
    }
}
