import { GameJsonConfig } from "../../GameJsonConfig";
import Tools from "../../Tools/Tools";
import { StorageKeys } from "../Storage/StorageEnum";
import { GameMode, GameModeInfo } from "../../gamePlaySystem/GameAttribute";
import GameEventSystem, { GameEvent } from "../GameEvent/GameEvent";

/**
 * 用户数据管理类
 * 单例
 */
export class UserDataMgr {
    private static _instance: UserDataMgr;
    public static get instance(): UserDataMgr {
        if (!UserDataMgr._instance) {
            UserDataMgr._instance = new UserDataMgr();
        }
        return UserDataMgr._instance;
    }

    private constructor() {
        // ai不需要兼容旧数据
        this._levelData = JSON.parse(cc.sys.localStorage.getItem(StorageKeys.LevelInfo) || '{}') || {};
        this._userData = JSON.parse(cc.sys.localStorage.getItem(StorageKeys.UserInfo) || '{}') || {};
    }

    private getLevelDataForGameMode(gameMode?: GameMode) {
        if (!gameMode) {
            gameMode = this.GetSelectedGameMode();
        }
        if (!gameMode) {
            gameMode = GameMode.NDRG;
        }
        
        if (!this._levelData[gameMode]) {
            this._levelData[gameMode] = { isPass: [], unLock: [], isLock: GameModeInfo[0].mode != gameMode, adCount: 0 };
        }
        return this._levelData[gameMode];
    }

    /** 用户配置 */
    protected _userData: {
        adKeyCount: number,
        unlockTime: number,
        selectedGameMode: string,
        musicVolume: number,
        soundVolume: number,
    }

    /**关卡数据
     * 数组结构，关卡索引为数组下标
     */
    private _levelData: { [gameMode in GameMode]: { isPass: boolean[], unLock: boolean[], isLock: boolean, adCount: number } }

    /**
     * 
     * @param level 
     * @param isUnlock 是否上锁
     */
    SaveLevelLock(level: number, isUnlock: boolean, save: boolean = true, gameMode?: GameMode | null) {
        if (!gameMode) {
            gameMode = this.GetSelectedGameMode();
        }
        if (!gameMode) return;
        const levelData = this.getLevelDataForGameMode(gameMode);
        levelData.unLock[level] = isUnlock;
        save && cc.sys.localStorage.setItem(StorageKeys.LevelInfo, JSON.stringify(this._levelData));
    }

    SaveLevelPass(level: number, isPass: boolean, save: boolean = true, gameMode?: GameMode) {
        if (!gameMode) {
            gameMode = this.GetSelectedGameMode();
        }
        if (!gameMode) return;
        const levelData = this.getLevelDataForGameMode(gameMode);
        levelData.isPass[level] = isPass;
        save && cc.sys.localStorage.setItem(StorageKeys.LevelInfo, JSON.stringify(this._levelData));
    }

    SaveLevelCfg(){
        cc.sys.localStorage.setItem(StorageKeys.LevelInfo, JSON.stringify(this._levelData));
    }
    
    SaveUserCfg(){
        cc.sys.localStorage.setItem(StorageKeys.UserInfo, JSON.stringify(this._userData));
    }

    public isPassedLevel(level: number, gameMode?: GameMode): boolean {
        if (!gameMode) {
            gameMode = this.GetSelectedGameMode();
        }
        if (!gameMode) return false;
        const levelData = this.getLevelDataForGameMode(gameMode);
        return levelData.isPass[level] ? true : false;
    }

    /**
     * 
     * @param level 
     * @returns ture 未上锁，false 上锁
     */
    public isUnLock(level: number, gameMode?: GameMode | null): boolean {
        if (Tools.GetQueryString("lock")) return true;
        if (!gameMode) {
            gameMode = this.GetSelectedGameMode();
        }
        if (!gameMode) return false;
        
        if(GameJsonConfig.GetIndex(level, gameMode) == 0) return true;//第一关不锁
        
        const levelData = this.getLevelDataForGameMode(gameMode);
        return UserDataMgr.instance.GetUnlockTime() || levelData.unLock[level] ? true : false;
    }

    AddAdKeyCount(){
        this._userData.adKeyCount = (this._userData.adKeyCount || 0) + 1;
        if(this._userData.adKeyCount >= 3){
            this._userData.adKeyCount -= 3;
            this._userData.unlockTime = Date.now() + 1000 * 60 * 60 * 24;
        }
        this.SaveUserCfg();
    }

    GetAdKeyCount(){
        return this._userData.adKeyCount;
    }

    reduceAdKey(){
        this._userData.adKeyCount = (this._userData.adKeyCount || 0) - 1;
        if(this._userData.adKeyCount < 0){
            this._userData.adKeyCount = 0;
        }
        this.SaveUserCfg();
    }

    GetUnlockTime(){
        if(this._userData.unlockTime && Date.now() > this._userData.unlockTime) return this._userData.unlockTime = null;
        return this._userData.unlockTime;
    }

    GetSelectedGameMode(): GameMode | null {
        return this._userData.selectedGameMode as GameMode || GameMode.NDRG;
    }

    SetSelectedGameMode(mode: GameMode){
        this._userData.selectedGameMode = mode;
        this.SaveUserCfg();
    }

    GetMusicVolume(): number {
        return this._userData.musicVolume !== undefined ? this._userData.musicVolume : 1.0;
    }

    SetMusicVolume(volume: number, isSave: boolean = true) {
        this._userData.musicVolume = volume;
        isSave && this.SaveUserCfg();
    }

    GetSoundVolume(): number {
        return this._userData.soundVolume !== undefined ? this._userData.soundVolume : 1.0;
    }

    SetSoundVolume(volume: number, isSave: boolean = true) {
        this._userData.soundVolume = volume;
        isSave && this.SaveUserCfg();
    }

    GetLvOrder(gameMode?: GameMode | null): number[] {
        if (!gameMode) {
            gameMode = this.GetSelectedGameMode();
        }
        if (!gameMode) {
            gameMode = GameMode.NDRG;
        }
        let orderStr = cc.sys.localStorage.getItem(StorageKeys.LvOrder + gameMode);
        if (orderStr) {
            return JSON.parse(orderStr);
        }
        let levels: number[] = [];
        const levelDatas = GameJsonConfig.getCurrentLevelDatas(gameMode);
        levelDatas.forEach(data => {
            if (data.level != -1) {
                levels.push(data.level);
            }
        });
        return levels;
    }

    SaveLvOrder(order: number[], gameMode?: GameMode | null) {
        if (!gameMode) {
            gameMode = this.GetSelectedGameMode() || GameMode.NDRG;
        }
        cc.sys.localStorage.setItem(StorageKeys.LvOrder + gameMode, JSON.stringify(order));
        GameEventSystem.dispatch(GameEvent.UpdateLvOrder);
    }

    /** 获取游戏模式解锁状态 */
    public IsGameModeUnlocked(gameMode: GameMode): boolean {
        const levelData = this.getLevelDataForGameMode(gameMode);
        return !levelData.isLock;
    }

    /** 解锁游戏模式 */
    public UnlockGameMode(gameMode: GameMode) {
        const levelData = this.getLevelDataForGameMode(gameMode);
        levelData.isLock = false;
        levelData.adCount = 0;
        this.SaveLevelCfg();
    }

    /** 获取游戏模式广告观看次数 */
    public GetGameModeAdCount(gameMode: GameMode): number {
        const levelData = this.getLevelDataForGameMode(gameMode);
        return levelData.adCount || 0;
    }

    /** 增加游戏模式广告观看次数 */
    public AddGameModeAdCount(gameMode: GameMode): number {
        const levelData = this.getLevelDataForGameMode(gameMode);
        if (!levelData.adCount) {
            levelData.adCount = 0;
        }
        levelData.adCount++;
        
        if (levelData.adCount >= 2) {
            levelData.isLock = false;
            levelData.adCount = 0;
        }
        
        this.SaveLevelCfg();
        return levelData.adCount;
    }

    /** 获取游戏模式已通过的关卡数 */
    public GetPassedLevelCount(gameMode: GameMode): number {
        const levelData = this.getLevelDataForGameMode(gameMode);
        let count = 0;
        if (levelData.isPass) {
            for (let key in levelData.isPass) {
                if (levelData.isPass[key]) {
                    count++;
                }
            }
        }
        return count;
    }

    /** 获取游戏模式总关卡数 */
    public GetTotalLevelCount(gameMode: GameMode): number {
        const levelDatas = GameJsonConfig.getCurrentLevelDatas(gameMode);
        return levelDatas.filter(data => data.level != -1).length;
    }
}