import BaseStorageValue from "./BaseStorageValue";

/**
 * 数值类型保存
 */
export default class NumberStorageValue extends BaseStorageValue<number> {

    private readonly _key : number;
    private _value : string;
    // 符号
    private symbol : number;

    set SetValue(value : number){
        this.symbol = value >= 0 ? 1 : -1;
        this._value = this.Xor(Math.abs(value) , this._key).toString(16);
        this.change = true;
    }
    get GetValue(): number {       
        return this.Xor(parseInt(this._value , 16) , this._key) * this.symbol;
    }
    public constructor(key : string , value : number , monitor : boolean = true){
        const _r = Math.random();
        const _key = Math.floor(_r * 10000000);
        super(key , value , monitor);
        this._key = _key;
        this.symbol = value >= 0 ? 1 : -1;
        this._value = this.Xor(Math.abs(value) , this._key).toString(16);
    }

    Save(_force : boolean = false) : any {
        if(this.change || _force){
            this.change = false;
            return this.Xor(parseInt(this._value , 16) , this._key) * this.symbol;
        }
        return null;
    }
    Load(value : any) {
        if(value == undefined || value == null || value === "") return;
        const _value : number = Number(value);
        if(!Number.isNaN(_value)){
            this.symbol = _value >= 0 ? 1 : -1;
            this._value = this.Xor(Math.abs(_value) , this._key).toString(16);
        }
        this.change = true;
    }

    private Xor(a,b){
        let _a=a.toString(2).split('').reverse();
        let _b=b.toString(2).split('').reverse();
        var L=Math.max(_a.length,_b.length),re=[];
        for(var i=0;i<L;i++){
            re.push(   _a[i]&& _b[i]?(  _a[i]!=_b[i]?1:0):( _a[i]||_b[i] )  )
        }       
        return parseInt( re.reverse().join(''),2);
    }
}