/**
 * 热更新管理器
 */
import DateUtil from "../DateUtil";

const RetryMaxCount = 999;

export type Manifest = {
    packageUrl: string;
    remoteManifestUrl: string;
    remoteVersionUrl: string;
    version: string;
    assets: {};
    searchPaths: any[];
}

export type UpdateEndCb = (type: number, manifestUrl?: string, files?: string[])=>{}
export type ProgressCb = (progress: number, desc: string)=>{}

class HotUpdateManager {
	/** 状态: 更新是否停止了 */
    _isStop: boolean;
	/** 状态: 更新中 */
    _updating: boolean;
	/** 状态: 可以尝试重新下载失败的文件 */
    _canRetry: boolean;
	/** 热更新模缓存根路径 */
    _writePath: any;
	/** 热更新模模块缓存路径 */
    _storagePath: string;
	/** 记录重新尝试下载文件的次数 */
    _reDownloadPath: {};
	/** 强制检测更新 */
    _isForcedUp: boolean;
	/** manifest文件路径 */
    _projectManifestUrl: string ;
    _tempProjectManifestUrl: string ;
    // _versionManifestUrl: string ;
    // _tempVersionManifestUrl: string ;
	/** 热更新对象 */
    _am: jsb.AssetsManager;
	/** 失败次数 */
    _failCount: number;
	/** 模块名 */
    _moduleName: string = 'main';
	/** 进度回调 */
    _progressCb?: ProgressCb;
	/** 结束回调 */
    _updateEndCb?: UpdateEndCb;

    constructor() {
    }
	
	init(){
		// 1.设置: 缓存保存路径
		this._writePath = this.getWritablePath();
		this._storagePath = this._writePath + 'module_'+ this._moduleName;
		this._projectManifestUrl = this._storagePath + '/project.manifest';
		this._tempProjectManifestUrl = this._storagePath + '_temp' + '/project.manifest.temp';
		// this._versionManifestUrl = this._storagePath + '/version.manifest';
		// this._tempVersionManifestUrl = this._storagePath + '_temp' + '/version.manifest.temp';
		
		let arr_version = this.getLocalManifes()?.version.split(':') || ['-1'];
		SingletonAttribute.config.hot_version = arr_version[0];
		console.log('hot update:','本地热更版本:', SingletonAttribute.config.hot_version);
	}

	getLocalManifes(): Manifest {
        if (!jsb.fileUtils.isFileExist('project.manifest')) {
            return;
        }

		let str = jsb.fileUtils.getStringFromFile('project.manifest'); 
		try{
			let obj = JSON.parse(str);
			console.log('hot update:','本地Manifes文件:', obj);
			return obj;
		}catch(e){
			console.error("hot update:",e);
			return null;
		}
	}

	/**
     * 启动热更新,同一时间只能使用一个
     * @param progressCb 进度回调
     * @param updateEndCb 结束回调
     * @param isForcedUp 强制热更新
     * @returns 
     */
	start (progressCb: ProgressCb, updateEndCb: UpdateEndCb, isForcedUp: boolean = false) {
		//web版不使用本场景
		if (!cc.sys.isNative || !SingletonAttribute.hot_update_trigger) {
			cc.log("no hot update:", SingletonAttribute.hot_update_trigger);
			return;
		}
		this.checkVerifyAssets();

		this._isStop = false
		this._updating = false
		this._canRetry = false
		this._reDownloadPath = {} // 重新尝试下载的文件
		this._isForcedUp = isForcedUp;// 强制检测更新
		this._progressCb = progressCb;
		this._updateEndCb = updateEndCb;


        if (!jsb.fileUtils.isDirectoryExist(this._writePath)) {
            jsb.fileUtils.createDirectory(this._writePath)
        }
		cc.log('hot update:', '热更新缓存路径 : ' + this._storagePath);

		// 2. 创建热更新对象
		this.CreateManifestFile(this._projectManifestUrl);
		// this.CreateManifestFile(this._versionManifestUrl);
		this._am = new jsb.AssetsManager(this._projectManifestUrl, this._storagePath, this.versionCompareHandle.bind(this));
		// this._am.loadLocalManifest( jsb.Manifest(customManifestStr, this._storagePath) , this._storagePath);

		// 3.设置: 下载完文件做校验是否完整 return true or false
		this._am.setVerifyCallback(function (path,asset) {
			// let exits = jsb.fileUtils.isFileExist(path);
			// if(!exits){
			// 	console.error("下载文件校验失败:", path, asset)
			// }
			// return exits;
			return true;
		});

		// 4.设置: 一些Android设备可能减慢下载过程当并发任务太多了。
		if (cc.sys.os === cc.sys.OS_ANDROID) {
			//值可能不准确,请做更多的测试,找到最适合你的游戏。
			this._am['setMaxConcurrentTask'](5);
		}

		// 5.检查更新
		this.checkUpdate();
	}

    /** 获得热更文件保存根目录 */
	getWritablePath(){
		this._writePath =  (jsb.fileUtils ? jsb.fileUtils.getWritablePath() : '/') +"hot-update/";
		return  this._writePath;
	}

    /** 创建热更配置文件 */
	CreateManifestFile(manifestUrl: string){
        if (jsb.fileUtils.isFileExist(manifestUrl)) {
			this.reSetHotUpdateUrl(manifestUrl, true);
            return manifestUrl;
        }

        if (!jsb.fileUtils.isDirectoryExist(this._storagePath)) {
            jsb.fileUtils.createDirectory(this._storagePath)
        }
        // let jsonText = jsb.fileUtils.getStringFromFile(manifestUrl) 
        // 打包新版本后首次启动时没有manifest配置, 需要重新生成保存在本地
        let packageUrl = SingletonAttribute.config.hot_update_url;
        let manifest = {
            packageUrl: packageUrl,
            remoteManifestUrl: `${packageUrl}project.manifest?t=${DateUtil.now()}`,
            remoteVersionUrl: `${packageUrl}version.manifest?t=${DateUtil.now()}`,
            version: '1',
            assets: {},
            searchPaths: []
        };
		console.log('hot update:',"生成 manifest: ", manifest);
        jsb.fileUtils.writeStringToFile(JSON.stringify(manifest), manifestUrl)
        return manifestUrl;
    }

	/** 重新设置热更地址 */
	reSetHotUpdateUrl(manifestUrl: string, resetVersion: boolean = false){
        let packageUrl = SingletonAttribute.config.hot_update_url;
		let manifestText: string = jsb.fileUtils.getStringFromFile(manifestUrl);
		let projectJson: any;
		try {
			projectJson = JSON.parse(manifestText);
		} catch (error) {
			console.error('hot update:',"manifest文件解析失败, 请检查文件格式是否正确: ", manifestText, manifestUrl);
			projectJson = {
				version: '1.0',
				assets: {},
				searchPaths: []
			};
		}
		// 热更地址有变动需要重启app
		const isChange = projectJson.packageUrl != packageUrl;

		projectJson["packageUrl"] = packageUrl;
		projectJson["remoteManifestUrl"] =  `${packageUrl}project.manifest?t=${DateUtil.now()}`;
		projectJson["remoteVersionUrl"] =  `${packageUrl}version.manifest?t=${DateUtil.now()}`;
		// if(resetVersion){
		// 	// 每次修改热更地址都要对比文件差异, 停用: 没文件更新时修改版本号会不停重启
		// 	projectJson["version"] = '0';
		// }
		console.log('hot update:', "重新设置热更地址: ", manifestUrl, projectJson);
        jsb.fileUtils.writeStringToFile(JSON.stringify(projectJson), manifestUrl);
		return isChange;
	}

	/** 重新设置刚下载的新版临时文件热更地址 */
	reSetTempHotUpdateUrl(){

		let change = false;
        if (jsb.fileUtils.isFileExist(this._tempProjectManifestUrl)) {
			change = this.reSetHotUpdateUrl(this._tempProjectManifestUrl) || change;
        }else{
			console.error("hot update:重设热更地址失败", this._tempProjectManifestUrl);
		}

        // if (jsb.fileUtils.isFileExist(this._tempVersionManifestUrl)) {
		// 	change = this.reSetHotUpdateUrl(this._tempVersionManifestUrl) || change;
        // }else{
		// 	console.error("hot update:重设热更地址失败", this._tempVersionManifestUrl);
		// }
		return change;
	}

    /** 启动检查更新 */ 
	checkUpdate () {
		if (this._updating) {
			this._progressCb(0, "检查更新中...")
			return;
		}
		// 初始化: 加载本地manifest文件
		if (this._am.getState() === jsb.AssetsManager.State.UNINITED) {
			this._am.loadLocalManifest(this._projectManifestUrl);
		}

		if (!this._am.getLocalManifest() || !this._am.getLocalManifest().isLoaded()) {
			console.error('hot update:',"读取本地manifest文件失败")
			return;
		}

		// 注册更新事件
		this._am.setEventCallback(this.updateCb.bind(this));
		// 启动检查更新
		this._am.checkUpdate();
		this._updating = true;
	}

    /** 下载更新文件状态 */ 
	updateCb (event: jsb.EventAssetsManager) {
		let needRestart = false;
		let alreadyUp = false;
		// cc.log("Code",event.getEventCode(),jsb.EventAssetsManager.UPDATE_FINISHED)
		switch (event.getEventCode())
		{
            // 没有本地manifest文件
			case jsb.EventAssetsManager.ERROR_NO_LOCAL_MANIFEST:
				console.warn('hot update:','没有本地manifest文件,热更新跳过.');
				alreadyUp = true;
				break;

            // 更新文件进度
			case jsb.EventAssetsManager.UPDATE_PROGRESSION:
				let msg = event.getMessage();
				if (msg) {
					console.log('hot update:', 'Updated file: ' + msg );
				}
				let desc = "正在更新 " + event.getDownloadedFiles() + "/" + event.getTotalFiles() + "..."
				console.log('hot update:', event.getDownloadedFiles() / event.getTotalFiles())
				this._progressCb(event.getDownloadedFiles() / event.getTotalFiles() || 0,desc)
				break;

            // 下载manifest失败
			case jsb.EventAssetsManager.ERROR_DOWNLOAD_MANIFEST:
            // 无法下载manifest文件
			case jsb.EventAssetsManager.ERROR_PARSE_MANIFEST:
				console.warn('hot update:', '无法下载manifest文件, 稍后重试: ', event.getMessage());
				this._updating = false;
				setTimeout(()=>{
					console.warn('hot update:', "尝试重新启动热更新")
					this.checkUpdate()
				}, 3000)
				break;
				
            // 已经是最新版本
			case jsb.EventAssetsManager.ALREADY_UP_TO_DATE:
				console.warn('hot update:', '已经是最新版本');
				alreadyUp = true;
				break;

            // 执行热更新
			case jsb.EventAssetsManager.NEW_VERSION_FOUND:
				if(this.reSetTempHotUpdateUrl()){
					needRestart = true
					console.warn('hot update:', '发现新版本, 准备重启再热更')
					this._progressCb(0,'发现新版本')
				}else{
					this._failCount = 0;
					this._am.update();
					this._updating = true;
					console.warn('hot update:', '发现新版本')
					this._progressCb(0,'发现新版本')
				}
				break;

            // 更新完成
			case jsb.EventAssetsManager.UPDATE_FINISHED:
				console.warn("hot update: 热更新完成, 准备重启, "+ event.getMessage())
				localStorage.setItem('checkVerifyHotAssets','1')
				needRestart = true;
				break;

            // 更新失败
			case jsb.EventAssetsManager.UPDATE_FAILED:
				console.warn('hot update:', '更新失败: ' + event.getMessage());
				this._updating = false;
				this._canRetry = true;
				//重新尝试下载
				if (!this._isStop)
					this.retry();
				break;

            // 某个文件更新失败
			case jsb.EventAssetsManager.ERROR_UPDATING:
				let path = event.getAssetId()
				this._reDownloadPath[path] = (this._reDownloadPath[path] || 0) + 1
				console.warn('hot update:', '资源更新错误: ' + path + ', ' + event.getMessage());
				// 尝试重新下载出问题的文件
				this.retry();
				break;

            // 解压zip文件失败
			case jsb.EventAssetsManager.ERROR_DECOMPRESS:
				console.warn('hot update:', "热更新解压zip文件失败",event.getMessage());
				break;
			default:
				break;
		}
	  
		// 更新完成
		if ( alreadyUp || needRestart){
			this._am.setEventCallback(null);
			this._updating = false;
			let call = this._updateEndCb; 
			this._updateEndCb   = null;
			if (needRestart) {
				this.saveSearchPaths();
				this._progressCb(1, "请稍后...")
				call(1, this._projectManifestUrl, this._am.getLocalManifest().getSearchPaths());  
			}else{
				console.log("hot: 没有发现更新")
				this._progressCb(1, "没有更新")
				call(0);
			}
		}
	}
    
    /**
	 * 对比版本是否相同
     * @param versionA 本地版本 "1121:2023xxxapp"
     * @param versionB 服务器版本 "1122:2023xxxapp"
     * @param return -1需要更新 0-1不用更新
     */
    versionCompareHandle(versionA: string, versionB: string) {
		console.log('hot update 对比版本:', versionA, versionB);
		let arrB = versionB.split(':')
		let appVesion = arrB[1];
		versionB = arrB[0];

		let arrA = versionA.split(':')
		versionA = arrA[0];
		// 先对比app版本是否匹配
		let sameAppVersion = appVesion == null || appVesion == SingletonAttribute.config.app_version;
		if(!sameAppVersion){
			console.error("hot update: 热更配置与本app版本不匹配, 不进行热更新:", arrB);
		}
		return !sameAppVersion || versionA == versionB ? 0 : -1;
    }

	/**
	 * 对比版本 return versionA < versionB ? -1 : 0
     * @param versionA 本地版本 "1121:2023xxxapp"
     * @param versionB 服务器版本 "1122:2023xxxapp"
     * @param return -1需要更新 0-1不用更新
     */
    versionCompareSize(versionA: string, versionB: string) {
		console.log('hot update versionCompareSize 对比版本:', versionA, versionB);
		let arrB = versionB.split(':')
		let appVesion = arrB[1];
		versionB = arrB[0];

		let arrA = versionA.split(':')
		versionA = arrA[0];
		// 先对比app版本是否匹配
		// let sameAppVersion = appVesion == null || appVesion == SingletonAttribute.config.app_version;
		// if(!sameAppVersion){
		// 	console.error("hot update: 热更配置与本app版本不匹配, 不进行热更新:", arrB);
		// 	return 0;
		// }
        var vA = versionA.split('.');
        var vB = versionB.split('.');
        for (var i = 0; i < vA.length; ++i) {
            var a = parseInt(vA[i]);
            var b = vB[i] ? parseInt(vB[i]) : 0;
            if (a === b) {
                continue;
            }else {
                return a < b ? -1 : 0;
            }
        }
		
		return vB.length > vA.length ? -1 : 0;
    }

    /** 尝试重新下载失败的文件 */ 
	retry () {
		if (!this._updating && this._canRetry) {
			this._canRetry = false;
			console.warn("hot update: 尝试重新下载失败的文件")            
			this._am.downloadFailedAssets();
		}
	}

    /** 更新搜索路径 */ 
	saveSearchPaths(){
		// 这个"HotUpdateSearchPaths"值将被检索和附加在游戏启动默认搜索路径
		// 重新添加主要的搜索路径。js是非常重要的,否则,新的脚本不会生效,对应的需要在 main.js里添加搜索路径
		// 添加搜索路径
		this.pushSearchPath(this._storagePath);
		var jsbsearchPaths = jsb.fileUtils.getSearchPaths();
		cc.sys.localStorage.setItem('HotUpdateSearchPaths', JSON.stringify(jsbsearchPaths));
	}

	// 移除下载文件
	removeDownloadFile(){
		jsb.fileUtils.removeDirectory(this._storagePath); // 移除热更新目录
		jsb.fileUtils.removeDirectory(this._storagePath+"_temp"); // 移除热更新目录
	}

	/** 删除热更新目录 */
	clearDownloadFileAll(){
		let dir = this.getWritablePath();
        if (jsb.fileUtils.isDirectoryExist(dir)) {
            jsb.fileUtils.removeDirectory(dir)
        }
	}

	getRemoteManifestUrl(){
        let packageUrl = SingletonAttribute.config.hot_update_url;
		return `${packageUrl}version.manifest?t=${DateUtil.now()}`
	}
    
	stop(){
		if (this._am){
            this._am.setVerifyCallback(null)
            this._am.setEventCallback(null)
        }
		delete this._am
	}
	
	// 增加搜索路径,并把该路径优先级设最高 searchPath = "dir/xxx"
	pushSearchPath(searchPath: string){
		var jsbsearchPaths = jsb.fileUtils.getSearchPaths();
		// 防止重复添加相同的搜索路径
		for (var j = 0; j < jsbsearchPaths.length; j++) {
			if (jsbsearchPaths[j] == searchPath){
				jsbsearchPaths.splice(j,1); // 删除相同的搜索路径,重置优先级
			}
		}
		jsbsearchPaths.unshift(searchPath)// 添加搜索路径
		jsb.fileUtils.setSearchPaths(jsbsearchPaths);
	}

	// 校验已下载热更资源是否完整
	checkVerifyAssets(){
		if(localStorage.getItem('checkVerifyHotAssets') != '1'){
			console.log("hot update:", '未热更新, 跳过校验')
			return;
		}
		
		let manifes = this.getLocalManifes()
		if(!manifes){
			console.warn('hot update', "没有manifes文件, 跳过校验");
			return;
		}

		localStorage.setItem('checkVerifyHotAssets','0')
		let isValid = true;
		for (const url in manifes.assets) {
			// asset.md5 
			// const asset = manifes.assets[url];
			let absPath = `${this._storagePath}/${url}`;
			if(!jsb.fileUtils.isFileExist(absPath)){
				isValid = false;
				break;
			}
		}

		// 校验失败重置热更缓存后再启动热更
		if(!isValid){
			HotUpdateSystem.removeDownloadFile();
			HotUpdateSystem.clearDownloadFileAll();
			console.error('hot update', "资源校验不通过");
		}else{
			console.warn('hot update', "verify ok");
		}
	}
}

export const HotUpdateSystem = new HotUpdateManager();