
export type LogicBlockCmds = Array<string | LogicItem | Array<LogicBlockCmds>>

/** 游戏主题/游戏模式 */
export enum GameMode {
	/** 脑洞热梗类 */
	NDRG = 'NDRG',	
	/** 拼图类 */
	HCZB = 'HCZB',
	JSQX = 'JSQX',
	SGYM = 'SGYM',
	ZJGG = 'ZJGG',
	
	ZBT = 'ZBT',

	KPQQ = 'KPQQ',
}

/** 游戏逻辑类型 */
export enum GameLogicType {
	/** 脑洞热梗 */
	NDRG = 'NDRG',	
	ZBT = 'ZBT',
	/** 剧情拼图 */
	JQPT = 'JQPT',
	KPQQ = 'KPQQ',
}

/** 游戏模式到游戏逻辑类型的映射 */
