export type HintConfig = {
	// 提示类型, 0没有提示、1图片、2文本列表
	hintType: number,
	/** 提示内容 */
	img: string,
	/** 提示位置 */
	texts: string[],
}

export type PageItem = {
	// 页面信息[完成条件变量, 背景路径]
	finish: string,
	bg: string,
	// 可摆放物品
	enter?: LogicBlockCmds;
	// 完成时执行的命令
	complete?: LogicBlockCmds;
	select: LogicBlockCmds;
}

export type LevelConfig = {
    errCount: number;
	timeout: number,
	name: string,
	progressName: string,
	progressCount: string,
	progressMax: number,
	goodsCount: number,
	music?: string, // 默认加载 common bundle: sound/${music}, 只需要指定文件名, 不需要指定路径
	/** 插件生成语音默认类型 */
	sound_type: string,
	hint: HintConfig,
	rule: LogicBlockCmds,
	cmds: LogicBlockCmds,
	/** 翻页游戏模式 专用 */
	pageCfg?: {
		pageNode: string,
		bgNode: string,
		pages: PageItem[],
	}

	/** 拼图游戏模式 专用 */
	puzzleCfg?: {
		bg?: string,
		/** 拼图横切分块数 */
		cut_x: number,
		/** 拼图竖切分块数 */
		cut_y: number,
		/** 游戏结束提示 */
		gameoverText: string,
	}
}

export type ActionItem = {
	/** 动作函数  to,by */
	func: string,
	repeatForever?: boolean,
	/** 持续时间 1*/
	dt: number,
	/** 参数, args: {x:1,y:9} */
	args: any,
}


export type LogicItem = {
	/** -----------  通用参数    ----------- */

	/** 模式 */
	mode: string;
	/** 执行条件,满足条件才执行该逻辑, 可以用&号分割多个判断 tag1&tag2==2*/
	if?: string;
	/** 不满足条件时执行else, 满足条件执行cmds */
	else?: LogicBlockCmds;
	/** 执行后续命令, 开头必须是 seq 或 !seq,代表顺序执行或并行 */
	cmds?: LogicBlockCmds;
	/** 被执行的节点们, 可以用&号分割多个节点: node1&node2&node3 */
	node?: string;
	nodeInclude?: string;
	/** 关卡内的全局变量+1, 用于条件判断 */
	var?: string;
	/** 子级cmds可以访问的本地属性 */
	args?: { [key: string]: any };
	/** 执行完成后延迟后续逻辑, 单位秒 */
	time?: number;
	/** 物品名, 本模块执行完成后物品显示到ui上 */
	goods?: string;
	goods_img?: string;
	/** 映射node名, 子级的cmds模块可以识别的node名字 (不常用) */
	namemap?: string,
	/** 执行完后隐藏node */
	hide?: boolean,
	/** 执行后顶置当前node */
	top?: number,
	/** 执行后置底部 */
	bottom?: number,
	/**切换图片 */
	changeSpriteframe?: boolean,
	resetAnchor?: boolean,
	/** 中断父级cmds流程,立即执行下一个逻辑, 两个按钮二选一的功能中用到此功能 */
	break?: boolean,
	/** 断开本逻辑上下逻辑关联，不再堵塞流程, 比如对话框不堵塞后续流程 */
	unlink?: boolean,
	/** 显示提示条件, 有些按钮按下会导致游戏失败，这些按钮不应该显示提示信息时就用到该判断 */
	if_hint?: string,

	/** -----------  专有参数    ----------- */

	/** drag||drop 模式专用, 控制拖动顺序 */
	group?: boolean,
	/** drag||drop 模式专用, 拖动到指定的 node(key) 后执行指定的逻辑 */
	to?: { [key: string]: LogicItem },
	/** drag||drop 模式专用, 例子说明: 被子和袜子不能同时放进洗衣机, 等待其中一条cmds逻辑执行完后才允许拖拽另个物品 */
	wait_drop_end?: boolean,
	/** drag||drop 模式专用, 允许重复拖拽同个物品 */
	redrag?: boolean,
	/** drag||drop 模式专用, 允许重复接收物品 */
	redrop?: boolean,
	/** drag||drop 模式专用, 拖动期间跟随手移动的图片node */
	cursor?: string,
	/** drag||drop 模式专用, 拖动期间跟随手移动的图片路径 */
	cursorImg?: string,
	/** drag||drop 模式专用, 拖动的图片下标名字 */
	index?: string,
	/** drag||drop 模式专用, 限制启动时拖动X范围不生效 */
	limitX?: boolean,

	/** chat 模式专用, 文本内容 */
	text?: string,
	/** chat 模式专用, 语音路径 */
	sound?: string,
	/** chat 模式专用, 插件生成语音默认类型, 支持 man、man_1、man_2、woman、woman_1、woman_2、boy、girl、old_man、old_woman*/
	sound_type?: string,

	/** anim 模式专用, 播放的动画名 */
	anim?: string,
	/** anim 模式专用, 等待播放完成再跑后续流程 */
	end_anim?: boolean,
	/** anim 模式专用, 等待播放完成再跑后续流程 */
	loop_anim?: boolean,
	/** anim 模式专用, 停止动画 */
	stop_anim?: boolean,

	/** def | run_def 模式专用, 定义逻辑模板名 */
	def?: string;
	/** act 模式专用, 对node执行指定的cc.tween动作 */
	acts?: ActionItem[];
	/** act 模式专用, 动作重复次数, -1永久重复执行 */
	act_repeat?: number;

	/** set_parent 模式专用, 切换父节点的名字 */
	parent?: string;
	/** pos 模式专用, 设置坐标 */
	pos?: { x: number, y: number };

	/** slot 模式专用, 切换龙骨动画插槽 */
	slot?: string;
	/** slot 模式专用, 切换龙骨动画插槽图片 */
	slot_idx?: number;
	/** slot 模式专用, 隐藏其余插槽 */
	show_slot?: {
		/** 类型, hide: 隐藏指定 slot_idx, show: 展示指定 slot_idx, showDef: 展示默认slot(data字段可以不填)*/
		type: 'hide' | 'show' | 'showDef',
		/**hide 类型下 slot_idx默认-1，该字段不用填写值 */
		data?: { slot: string; slot_idx: number }[],
		/** 缓存插槽默认值 */
		cacheDef?: boolean,
		/**展示插槽默认值 */
		showDef?: boolean,
	};

	/** switch 模式专用, 条件if else判断, key填if条件 */
	switch?: { [key: string]: LogicBlockCmds };
	/** switch 模式专用, switch语句的default字段相当于else */
	switch_default?: LogicBlockCmds;
	/** for 模式专用, 步进数,"i+=1" */
	for_step?: string;
	/** for 模式专用, 是否异步并行执行cmds内容 */
	for_async?: boolean;
	/** 检查透明像素 的节点 */
	transparentNodes?: string[]

	/** 翻页游戏模式 专用, 翻页游戏模式下的item名字, 同时用于拖拽时显示图片,路径自动添加dragImg/前缀 */
	sl_item?: string;
	/** 翻页游戏模式 专用, item 放置的位置node */
	place?: string;
	/** 翻页游戏模式 专用, 摆放后动画皮肤切换,[sk节点, 骨骼名称, 切换皮肤idx, 默认皮肤idx] */
	sk_idxs?: string[]
}

