    public static HasSkCache(sk: sp.Skeleton, animName: string) {
        if (sk.isAnimationCached()) {
            if(CC_JSB){
                return sp.spine['skeletonCacheMgr'] && sp.spine['skeletonCacheMgr'].hasAnimation(sk.skeletonData['_uuid'], animName);
            }else{
                let cache = sk?._skeletonCache?._skeletonCache[sk.skeletonData['_uuid']];
                let animCache // :cc.AnimationCache
                if (cache && (animCache = cache.animationsCache[animName])) {
                    return animCache;
                }
            }
        }
        
        return;
    }

    /**
     * 缓存模式下 立刻缓存sk所有动画数据
     * @param sk 
     * @returns 
     */
    public static updateAnimationCache(sk: sp.Skeleton) {
        if (sk.isAnimationCached()) {
            let _skeleton = sk['_skeleton']
            for (let i = 0, len = _skeleton.data.animations.length; i < len; i++) {
                let animationName = _skeleton.data.animations[i].name
                if (!SpineHelper.HasSkCache(sk, animationName)) {
                    sk.updateAnimationCache(animationName);
                }
            }
        }
    }

    public static updateAnimationCache1(sk: sp.Skeleton) {
        if (!sk["_skeleton"] || !sk["_skeleton"].data || !sk["_skeleton"].data.animations) {
            return Logger.warn("预播放失败", sk.node.name);
        }

        if (sk.isAnimationCached()) {
            for (let i = 0; i < sk["_skeleton"].data.animations.length; i++) {
                const animInfo = sk["_skeleton"].data.animations[i];
                if (!SpineHelper.HasSkCache(sk, animInfo.name)) {
                    sk.updateAnimationCache(animInfo.name);
                    // let _cache = SpineHelper.GetSkCache(this.sk, animInfo.name);
                    // _cache && DebugSet(_cache,'isCompleted') //检查缓存失效位置
                }
                sk.setAnimation(0, animInfo.name, false);
            }
        }
    }

    public static RealesSkCacheAll(sk: sp.Skeleton){
        if (sk._skeletonCache) {
            if (sk._cacheMode === sp.Skeleton.AnimationCacheMode.SHARED_CACHE) {
                sk._skeletonCache._skeletonCache = {}
            }
        }
    }
    
    public static RealesSpineCacheAll(){
        CC_JSB && sp.spine['skeletonCacheMgr'] && sp.spine['skeletonCacheMgr'].clearAll();
    }
