export default class JsonAssetEx extends cc.JsonAsset {
    public _nativeAsset: any;
    public json: any;
}

cc.assetManager['factory'].register('jsonc', (id, data, options, onComplete)=>{
    let out = new JsonAssetEx();
    out['_nativeUrl'] = id;
    out['text'] = data;
    out['json'] = JSONC.parse(data);
    onComplete && onComplete(null, out);
})