import { BundleGroupType } from "../../Const/GameConst";
import { GameJsonConfig } from "../../GameJsonConfig";
import { GmManger } from "../../System/GmManger";
import SoundSystem from "../../System/Sound/SoundManager";
import { UserDataMgr } from "../../System/User/UserDataMgr";
import UIManager from "../../System/ui/UIManager";
import { ViewConfig } from "../../System/ui/UI_Config";
import CheckOnTransparent from "../../Tools/CheckTransparentClick";
import Timer from "../../Tools/Timer";
import ResourcesManager from "../../engine/ResourceManager";
import GameData from "../../game/GameData";
import GameJqptView from "../../game/ui/GameJqptView";
import Singleton from "../../singleton/Singleton";
import { GameLogicType, GameMode, GameModeTypeMap, GameViewEvent, LevelConfig, LogicItem } from "../GameAttribute";
import { BaseLogicBlock, HintInfo } from "../LogicBlock/BaseLogicBlock";
import { LogicBlock } from "../LogicBlock/LogicBlock";

export class BasicGameManger {
	protected game_view: any;

	protected lv: number;
	protected bundle_name: string;
	protected game_node: cc.Node;
	protected startTime: number;
	/** 关卡配置中的变量 */
	protected lv_vlaues: {[key: string]: number | string} = {};
	protected lv_config: LevelConfig;
	/**游戏场景内所有游戏node */
	protected lv_nodes: {[key: string]: cc.Node} = {};
	protected logic_blocks: BaseLogicBlock[] = [];
	protected isValid = true;
	protected logic_template: {[key: string]: LogicItem} = {};
	protected timeout: number;
	private talkLayer: number;
	protected cursor_node: cc.Node;
	last_timeout: string;
	isGameOver: boolean;
	get CursorNode(){
		return this.cursor_node;
	}
    protected errCount: number = 3;
	constructor(){}

	/**
	 * 设置到对话层级
	 */
	public SetToTalkLayer(node: cc.Node){
		node.zIndex = this.talkLayer;
		this.talkLayer++;
	}

	get BundleName(){
		return this.bundle_name;
	}
	
	get GameNode(){
		return this.game_node;
	}

	get Level(){
		return this.lv;
	}
	
	/** 跳到下一关 */
	gotoNextLevel(callback?: ()=>any){
		const gameMode = UserDataMgr.instance.GetSelectedGameMode();
		let level = GameJsonConfig.getNextLevel(this.Level, gameMode);
		if(level == null){
			console.error("关卡不存在: ", level);
		}else{
			GameData.gotoLevel(level, gameMode, callback);
			return true;
		}
	}
	
	/** 是否有下一关 */
	hasNextLevel(){
		const gameMode = UserDataMgr.instance.GetSelectedGameMode();
		return GameJsonConfig.getNextLevel(this.Level, gameMode) != null;
	}
	
	createGame(level: number, callback: Function){
		this.lv = level;
		const gameMode = UserDataMgr.instance.GetSelectedGameMode();
		const gameType = GameModeTypeMap[gameMode];
		!GameJsonConfig.json_setting_lv[gameMode]?.[level] && console.error("关卡不存在: ", level, "使用默认关卡配置")
		this.bundle_name = GameJsonConfig.json_setting_lv[gameMode]?.[level]?.bundleName || "level_"+level;
		UIManager.instance.showLoadingIcon();
		ResourcesManager.instance.loadBundle("common", (_)=>{
			ResourcesManager.instance.loadBundleAndLoadAllResInBundle(this.bundle_name, (_,bundle)=>{
				// Select the appropriate GameView based on game mode
				let viewConfig = ViewConfig.GameView;
				if (gameType === GameLogicType.ZBT) {
					viewConfig = ViewConfig.GameZbtView;
				}else if (gameType === GameLogicType.NDRG) {
					viewConfig = ViewConfig.GameNdrgView;
				}else if (gameType === GameLogicType.JQPT) {
					viewConfig = ViewConfig.GameJqptView;
				}
				// Add more game modes here as needed
				
				UIManager.instance.showView(viewConfig, (view)=>{
					UIManager.instance.hideLoadingIcon();
					this.game_view = view as any;

					// 加载关卡prefab
					let itemNode = bundle.get(this.bundle_name, cc.Prefab);
					if(itemNode){
						this.game_node = cc.instantiate(itemNode);
						this.talkLayer = this.game_node.childrenCount + 1;
						this.game_node.x = 0;
						this.game_node.y = 0;
						this.game_view.addLvContent(this.game_node);
						this.cursor_node = new cc.Node();
						this.cursor_node.parent = this.game_view.node;
						this.cursor_node.name = "cursorImg";
						this.cursor_node.addComponent(cc.Sprite);
						this.cursor_node.active = false;
					}
					
					// 加载关卡配置
					let cfg_assets = bundle.get('cfg_'+this.bundle_name);
					if(cfg_assets && cfg_assets['_$nativeAsset']){
						this.lv_config = JSONC.parse(cfg_assets['_$nativeAsset']);
					}
					
					if(!this.lv_config){
						console.error('this.lv_config 配置不存在: ', this.bundle_name);
					}
					if(this.lv_config.music){
						SoundSystem.StopBgm();
						SoundSystem.PlayBgm("common", "music/"+this.lv_config.music);
					}
					this.onLoadConfig();
					callback && callback(this);
				}, level);
			}, BundleGroupType.Game)
		}, BundleGroupType.Game)
	}
	
	// 加载关卡配置, 具体实现看游戏类型
	onLoadConfig(){}

	/** 拖拽到目标节点上失败, 回调方法 */
	onDragFail(pos: cc.Vec2, config: LogicItem){}
	
	/** 复活 */
	revive() {
		this.errCount < 3 && this.setErrCount(3);
		this.addTime(60);
		this.resume();
	}

	updateLabelStatus(dt: number){
		if(!GmManger.inst.freeTimeValue){
			this.timeout = this.timeout - dt;
		}
		this.timeout = Math.max(this.timeout, 0);
		let str_timeout = ''+Math.floor(this.timeout)
		if(str_timeout != this.last_timeout && str_timeout == '3'){
			Singleton.SoundSystem.PlaySound("resources", "sound/timeout");
		}
		this.last_timeout = str_timeout;
		
		this.game_view.setTimeout(str_timeout, this.timeout / this.lv_config.timeout);
		this.game_view.setProgress(this.lv_config.progressName, +this.getValue(this.lv_config.progressCount), this.lv_config.progressMax);
		if(this.timeout == 0){
			this.pause();
			this.onGameOver(false);
			// UIManager.instance.showView(ViewConfig.GameTimeoutPanel, ()=>{});
			console.log("超时了")
		}
	}

	/** 增加倒计时 */
	addTime(time: number){
		this.timeout += time;
	}
	
	addErrCount(count: number){
		this.errCount += count;
		this.game_view.setErrCount(this.errCount);
	}

    setErrCount(count: number){
        this.errCount = count;
        this.game_view.setErrCount(count);
        if(this.errCount <= 0){
            this.errCount = 0;
            this.onGameOver(false);
        }
    }

	onViewEvent(event: GameViewEvent){
		
	}


	/** 深度遍历所有game_node node name保存到 this.lv_nodes */
	updateNodeKeys(node: cc.Node){
		for(let child of node.children){
			if(CC_DEBUG && this.lv_nodes[child.name] && child.name[0] != '_'){
				console.error('场景中不能存在重复的节点名！！:', child['getPath']());
			}
			this.lv_nodes[child.name] = child;
			this.updateNodeKeys(child);
		}
	}
	
	getValue(key: string){
		return this.lv_vlaues[key];
	}

	
	addValue(key: string){
		this.lv_vlaues[key] = this.lv_vlaues[key] ? (+this.lv_vlaues[key]+1) : 1;
	}
	
	setValue(key: string, value: number){
		this.lv_vlaues[key] = value;
	}


	addGoodsItem(name: string, img: cc.SpriteFrame){
		this.game_view.setGoodsItem(name, img);
	}

	onCompleteEvent(mode: string){
		this.game_view.onCompleteEvent(mode);
	}

	getNode(name: string){
		return this.lv_nodes[name];
	}

	getNodes(str: string): cc.Node[]{
		let out: cc.Node[] = [];	
		for (const key in this.lv_nodes) {
			if (Object.prototype.hasOwnProperty.call(this.lv_nodes, key)) {
					key.includes(str) && out.push(this.lv_nodes[key]);
			}
		}
		return out;
	}
	
	addNode(node: cc.Node, name: string){
		if(CC_DEBUG && this.lv_nodes[name]){
			console.error('addNode 场景中已经存在该节点！！:', name);
		}
		return this.lv_nodes[name] = node;
	}
	
	addLogicTemplate(logicItem: LogicItem){
		return this.logic_template[logicItem.def] = logicItem;
	}
	
	getLogicTemplate(defName: string){
		if(CC_DEBUG && !this.logic_template[defName]){
			console.error('getLogicTemplate 模板不存在！！:', defName);
		}
		return this.logic_template[defName];
	}

	/** 恢复游戏 */
	resume(){
		Timer.loop(500, this, this.updateLabelStatus);
	}

	/** 暂停游戏 */
	pause(){
		Timer.clear(this, this.updateLabelStatus);
	}
	
	removeNode(node: cc.Node, name: string){
		if(this.lv_nodes[name] == node){
			delete this.lv_nodes[name];
			return true;
		}else{
			console.error('removeNode 删除节点不匹配！！:', name);
		}
	}


	/** 游戏结束 */
	onGameOver(is_win: boolean){
		this.isGameOver = true;
		this.pause()
		if(is_win){
			const gameMode = UserDataMgr.instance.GetSelectedGameMode();
			UserDataMgr.instance.SaveLevelPass(+this.Level, true, false, gameMode);
			UserDataMgr.instance.SaveLevelLock(+this.Level, true, false, gameMode);
			let level = GameJsonConfig.getNextLevel(this.Level, gameMode);
			if(level != null){
				UserDataMgr.instance.SaveLevelLock(level, true, false, gameMode);
			}
			UserDataMgr.instance.SaveLevelCfg();
			Singleton.SoundSystem.PlaySound("resources", "sound/win");
		}else{
			Singleton.SoundSystem.PlaySound("resources", "sound/fail");
		}
		Timer.once(500, this, ()=>{
			this.onOpenGameOverUi(is_win);
		});
	}

	onOpenGameOverUi(is_win: boolean){
		UIManager.instance.showView(ViewConfig.SettlementView, (view)=>{ }, is_win)
	}

	addLogicBlock(lb: BaseLogicBlock){
		this.logic_blocks.push(lb);
	}

	getHintInfo(): HintInfo{
		for (let i = 0; i < this.logic_blocks.length; i++) {
			const lc = this.logic_blocks[i];
			const info = lc.getHintInfo();
			if(info){
				return info;
			}
		}
	}
	
	/** 获取 node 属性值
	 * @param valueKey 属性名, 格式: "node.size.width"
	 * @param localNodes 局部nodes
	 */
	getNodeAttr(valueKey: string, localNodes?: {[key: string]: cc.Node}){
		let arr = valueKey.split('.');
		if(arr.length <= 1){
			return
		}
		let v: any = localNodes ? (localNodes[arr[0]] || this.lv_nodes[arr[0]]) : this.lv_nodes[arr[0]];
		if(v == null){
			console.error('getNodeAttr 节点不存在: ',arr[0], valueKey);
			return
		}
		for (let i = 1; i < arr.length; i++) {
			v = v[arr[i]];
			if(v == null){
				console.error('getNodeAttr 节点属性不存在: ',arr[i], valueKey);
				break;
			}
		}
		return v;
	}

	/** 格式化变量值, valueStr = "${count}/数量" 转换为 "1/数量" */
	formatValueString(valueStr: any, defaultValue?: string | number, localNodes?: {[key: string]: cc.Node}, getValueFunc?: (key: string)=>any){
		if(typeof valueStr != 'string'){
			return valueStr;
		}

		while(true){
			let reg = valueStr.match(/\${(.+)}/);
			if(!reg){
				break;
			}
			let valueKey = reg[1]; // valueKey = "count" || "node.size.width"
			let v = getValueFunc ? getValueFunc(valueKey) : this.lv_vlaues[valueKey];
			if(v == null){
				v = this.getNodeAttr(valueKey, localNodes);
			}
			v == null && defaultValue == null && console.error('格式化变量值失败: ',valueKey, '变量不存在')
			valueStr = valueStr.replace(reg[0], v != null ? v : defaultValue);
		}
		return valueStr;
	}

	/** 格式化参数变量值, args = {x:"${node.x}", y:${count}, z:0} 转换为 {x:1, y:2, z:0}*/
	formatArgsValue(args: object | Array<any>, convertToNumber: boolean = false, localNodes?: {[key: string]: cc.Node}, getValueFunc?: (key: string)=>any): any{
        if (args == null) return null;
        let _data = Array.isArray(args) ? [] : {};
        const _keys = Object.keys(args);

        _keys.forEach((value) => {
            if (typeof (args[value]) == "object") {
                _data[value] = this.formatArgsValue(args[value], convertToNumber, localNodes, getValueFunc);
			}else if(typeof (args[value]) == "string"){
				_data[value] = this.formatValueString(args[value], null, localNodes, getValueFunc);
				if(convertToNumber){
					_data[value] = Number(_data[value]);
					isNaN(_data[value]) ? console.error('格式化参数变量值失败: ',value, '不是数字') : null;
				}
            } else{
                _data[value] = args[value]
			}
        });
        return _data ;
	}	
	
	removeLogicBlock(lb: BaseLogicBlock){
		if(!this.isValid){
			return;
		}
		let index = this.logic_blocks.indexOf(lb);
		if(index > -1){
			this.logic_blocks.splice(index, 1);
		}
	}

	runLoginc(logicItem: LogicItem){
		new LogicBlock(logicItem);
	}

	/** 加载资源,安全回调 */
	loadRes(url: string, type: any, callback?: (res: any)=>void){
		ResourcesManager.instance.loadResByBundleNameAndPaths(this.BundleName, url, type, (res: any)=>{
			if(!this.isValid){
				return;
			}
			if(callback){
				callback(res);
			}
		}, BundleGroupType.Game);
	}
	
	/** 获得拖拽期间的图片 */
	getCursorNode(cursorImgPath: string): cc.Node {
		this.cursor_node.getComponent(cc.Sprite).spriteFrame = null;
		this.loadRes(cursorImgPath, cc.SpriteFrame, (res: cc.SpriteFrame)=>{
			this.cursor_node.getComponent(cc.Sprite).spriteFrame = res;
		});

		// 停止之前的动作
		this.cursor_node.stopAllActions();

		// 计算最小值并判断是否需要缩放
		let minSize = Math.min(this.cursor_node.width, this.cursor_node.height);
		let scaleRatio = 1;
		if (minSize > 200) {
			scaleRatio = 200 / minSize;
		}
		
		// 设置初始缩放值
		this.cursor_node.scale = scaleRatio;
		this.cursor_node.opacity = 0;
		
		// 播放动作: 变回原始缩放值,并淡入
		cc.tween(this.cursor_node)
			.to(0.15, { opacity: 255, scale: 1 })
			.start();
		
		return this.cursor_node;
	}

	/**
	 * 结束关卡
	 */
	public EndGame(){
		this.onDestory();
		CheckOnTransparent.clear();
	}

	private onDestory(){
		this.isValid = false;
		this.game_view.closeView();
		Timer.clearAll(this);
		this.lv_vlaues = null;
		for (let i = this.logic_blocks.length-1; i >= 0; i--) {
			const lb = this.logic_blocks[i];
			lb.onDestory();
		}
		this.logic_blocks.length = 0;
		Timer.clearAll(this);
		ResourcesManager.instance.unLoadBundleAndReleaseAllByBundleGroupType(BundleGroupType.Game);
	}

}
