import { UserDataMgr } from "../../System/User/UserDataMgr";
import { GameJsonConfig } from "../../GameJsonConfig";
import GmLvOrderView from "./GmLvOrderView";
import { SinglePageItemCount } from "../../gamePlaySystem/GameAttribute";

const {ccclass, property} = cc._decorator;

@ccclass
export default class LvOrderItem extends cc.Component {

    @property({ type: cc.Label, displayName: '' })
    indexLbl: cc.Label = null;

    @property({ type: cc.Label, displayName: '' })
    nameLbl: cc.Label = null;

    @property({ type: cc.Label, displayName: '' })
    pageNumLbl: cc.Label = null;

    private _name: string = "";
    public id: number = -1;
    public index: number = -1;
    public pageNum: number = -1;
    public dlgLvOrder: GmLvOrderView = null;

    init(id: number, index: number, dlgLvOrder: GmLvOrderView) {
        this.id = id;
        this.index = index;
        this.dlgLvOrder = dlgLvOrder;
        this.pageNum = Math.floor(this.index / SinglePageItemCount) + 1;
        this.indexLbl.string = (this.index + 1).toString();
        this.pageNumLbl.string = this.pageNum.toString();
        this.updateName();

        if (dlgLvOrder) {
            this.node.on(cc.Node.EventType.TOUCH_START, this.onTouchStart, this);
            this.node.on(cc.Node.EventType.TOUCH_MOVE, this.onTouchMove, this);
            this.node.on(cc.Node.EventType.TOUCH_END, this.onTouchEnd, this);
            this.node.on(cc.Node.EventType.TOUCH_CANCEL, this.onTouchEnd, this);
        }
    }

    onTouchStart(event: cc.Event.EventTouch) {
        this.dlgLvOrder.onItemTouchStart(event, this);
    }

    onTouchMove(event: cc.Event.EventTouch) {
        this.dlgLvOrder.onItemTouchMove(event, this);
    }

    onTouchEnd(event: cc.Event.EventTouch) {
        this.dlgLvOrder.onItemTouchEnd(event, this);
    }

    changeId(id: number) {
        this.id = id;
        this.updateName();
    }

    updateName() {
        const levelData = GameJsonConfig.json_setting_lv[UserDataMgr.instance.GetSelectedGameMode()]?.[this.id];
        if (levelData) {
            this._name = levelData.title || `Level ${this.id}`;
            this.nameLbl.string = this._name;
        }
    }

    updateIndexLabel() {
        this.indexLbl.string = (this.index + 1).toString();
    }
}
