import { GameJsonConfig } from "../../../GameJsonConfig";
import { GameEvent } from "../../../System/GameEvent/GameEvent";
import ViewBase from "../../../engine/ViewBase";
import { GameMode, IsettingJson, ILevelData, SinglePageItemCount, GameModeInfo } from "../../../gamePlaySystem/GameAttribute";
import Singleton from "../../../singleton/Singleton";
import PageCom from "./PageCom";
import Timer from "../../../Tools/Timer";
import { UserDataMgr } from "../../../System/User/UserDataMgr";

let isEnterLvPage = false;
const { ccclass } = cc._decorator;

@ccclass
export default class LevelPageView extends ViewBase {

    private pageView: cc.PageView = null;
    private pageItem: cc.Node = null;
    private Label_level: cc.Label;
    // private adTimeout: cc.Label;

    private _pageCount: number;
    private currentPageIndex: number = 0;
    private currentGameMode: GameMode = null;
    start() {
        this.node.on("scroll-ended", this.onScrollEnded, this);
        this.ReflashPageLabel();
    }

    onLoad(): void {
        this.pageView = this.node.getComponent(cc.PageView);
        this.pageItem = this.getChild(this.node, "myPage");
		this.onAddEvent(this.getChild(this.node, "left"), () => { this.onClick_leftBtn() });
		this.onAddEvent(this.getChild(this.node, "right"), () => { this.onClick_rightBtn() });
		this.onAddEvent(this.getChild(this.node, "left_last"), () => { this.onClick_leftBtn(true) });
		this.onAddEvent(this.getChild(this.node, "right_last"), () => { this.onClick_rightBtn(true) });
		this.Label_level = this.getChild(this.node, "Label_level").getComponent(cc.Label);
        // this.initGamesBtn();
    }

    onEnable() {
        this.pageView.getComponentsInChildren(PageCom).forEach(v=>v.RefashPageView())
        // 广告解锁关卡时刷新页面
        Singleton.GameEventSystem.on(GameEvent.UP_HOME_UI, this, () => {
            this.node.getComponentsInChildren(PageCom).forEach(v=>v.RefashPageView())
        })
        // 关卡顺序调整时刷新关卡列表
        Singleton.GameEventSystem.on(GameEvent.UpdateLvOrder, this, () => {
            this.node.activeInHierarchy && this.ReflashLvList();
        })
    }

    onDisable(): void {
        Singleton.GameEventSystem.clear(this);
        Timer.clearAll(this);
    }

    /** 用于跟踪已加载页面的索引和节点。 */
    private loadedPages: Map<number, cc.Node> = new Map();
    /** 用于缓存被移除的页面节点，避免频繁创建/销毁。 */
    private pagePool: Map<number, cc.Node> = new Map();
    /** 记录上次已加载的当前页索引，防止重复刷新。 */
    private lastLoadedIndex: number = -1;

    /** 刷新关卡列表 */
    ReflashLvList() {
        isEnterLvPage = true;
        this.currentGameMode = UserDataMgr.instance.GetSelectedGameMode();

        // 清除所有已加载的页面（先移除，再放到暂存池）
        this.pageView.removeAllPages();
        this.loadedPages.forEach((node, index) => { node.destroy(); });
        this.loadedPages.clear();
        this.pagePool.forEach((node, index) => { node.destroy(); });
        this.pagePool.clear();
        this.lastLoadedIndex = -1;

        let lvOrder = UserDataMgr.instance.GetLvOrder(this.currentGameMode);
        this._pageCount = Math.ceil(lvOrder.length / SinglePageItemCount);
        this.currentPageIndex = 0;
        // 加载当前页及其邻页
        this.updateLoadedPages(0);
    }

    /** 根据关卡顺序获取排序后的关卡数据 */
    private getOrderedLevelDatas(): ILevelData[] {
        let lvOrder = UserDataMgr.instance.GetLvOrder(this.currentGameMode);
        let allDatas = GameJsonConfig.json_setting_lv[this.currentGameMode];
        let orderedDatas: ILevelData[] = [];

        for (let i = 0; i < lvOrder.length; i++) {
            let levelId = lvOrder[i];
            if (allDatas && allDatas[levelId]) {
                orderedDatas.push(allDatas[levelId]);
            }
        }

        return orderedDatas;
    }

    private loadPage(index: number, orderedDatas: ILevelData[]) {
        if (this.loadedPages.has(index)) return;

        let _datas = orderedDatas.slice(SinglePageItemCount * index, SinglePageItemCount * (index + 1));
        if (_datas.length === 0) return;

        // 优先从暂存池取页面
        let pageNode = this.pagePool.get(index);
        if (pageNode) {
            this.pagePool.delete(index);
            pageNode.active = true;
            pageNode.name = `${index}`;
            this.pageView.addPage(pageNode);
            pageNode.getComponent(PageCom).RefashPageView()//SetData(_datas, index);
            this.loadedPages.set(index, pageNode);
            return;
        }

        // 直接创建新页面
        let newP = cc.instantiate(this.pageItem);
        newP.name = `${index}`;
        this.pageView.addPage(newP);
        newP.addComponent(PageCom);
        newP.active = true;
        newP.getComponent(PageCom).SetData(_datas, index, this.currentGameMode);
        this.loadedPages.set(index, newP);
    }

    private unloadPage(index: number) {
        if (!this.loadedPages.has(index)) return;
        let node = this.loadedPages.get(index);
        this.pageView.removePage(node);
        node.active = false;
        this.pagePool.set(index, node);
        this.loadedPages.delete(index);
    }

    private updateLoadedPages(currentIndex: number) {
        // 避免重复刷新同一页面（例如重复触发 scroll-ended）
        if (this.lastLoadedIndex === currentIndex) return;
        this.lastLoadedIndex = currentIndex;

        // 先移除所有当前加载的页面到缓存池，防止顺序混乱
        this.loadedPages.forEach((node, index) => {
            this.pageView.removePage(node);
            node.active = false;
            node.destroy();
            // this.pagePool.set(index, node);
        });
        this.loadedPages.clear();

        // 获取排序后的关卡数据（只获取一次）
        let orderedDatas = this.getOrderedLevelDatas();

        // 重新加载需要的页面（左、中、右）
        let pagesToLoad = [currentIndex - 1, currentIndex, currentIndex + 1].filter(i => i >= 0 && i < this._pageCount);
        pagesToLoad.forEach(i => this.loadPage(i, orderedDatas));

        // 设置透明度：只显示加载的页面
        this.pageView.content.children.forEach(child => {
            child.opacity = 0;
        });
        pagesToLoad.forEach(i => {
            if (this.loadedPages.has(i)) {
                this.loadedPages.get(i).opacity = 255;
            }
        });

        // 设置 PageView 的当前页面为中间的页面（索引1）
        let idx = currentIndex === 0 ? 0 : 1;
        // console.warn(`设置当前页面索引为 ${idx}，对应实际页面索引 ${currentIndex}`);
        this.pageView.scrollToPage(idx, 0);
        this.ReflashPageLabel();
    }

    onScrollEnded(_) {
        const oldIndex = this.currentPageIndex;
        let pageIndex = this.pageView.getCurrentPageIndex();
        if (pageIndex === 0 && oldIndex > 0) {
            this.currentPageIndex = oldIndex - 1;
        } else if (pageIndex === 2 && oldIndex < this._pageCount - 1) {
            this.currentPageIndex = oldIndex + 1;
        } else if (pageIndex === 1 && oldIndex == 0) {
            // 从第一页向右滚动
            this.currentPageIndex ++;
        } else {
            return;
        }
        this.updateLoadedPages(this.currentPageIndex);
    }

    ReflashPageLabel() {
        this.Label_level.string = (this.currentPageIndex + 1) + "/" + this._pageCount;
    }

    private onClick_leftBtn(isLast: boolean = false) {
        if (this.currentPageIndex > 0) {
            this.currentPageIndex--;
        } else {
            this.currentPageIndex = this._pageCount - 1;
        }
        if(isLast) this.currentPageIndex = 0;
        this.updateLoadedPages(this.currentPageIndex);
    }

    private onClick_rightBtn(isLast: boolean = false) {
        if (this.currentPageIndex < this._pageCount - 1) {
            this.currentPageIndex++;
        } else {
            this.currentPageIndex = 0;
        }
        if(isLast) this.currentPageIndex = this._pageCount - 1;
        this.updateLoadedPages(this.currentPageIndex);
    }
}
