import { Logger } from "../engine/Logger";

export default class ByteDanceAppHelper {

    private static init_resolve_func : Function;
    private static init_reject_func : Function;

    private static login_resolve_func : Function;
    private static login_reject_func : Function;

    private static logout_resolve_func : Function;
    private static logout_reject_func : Function;

    private static risk_resolve_func : Function;
    private static risk_reject_func : Function;

    private static pay_resolve_func : Function;
    private static pay_reject_func : Function;

    /** 初始化 */
    public static GBCommonSDK_Init(){
        if(!CC_JSB) return;
        jsb.reflection.callStaticMethod("org/cocos2dx/javascript/AppActivity" , "GBCommonSDK_Init" , "()V");
        return new Promise((r,j)=>{
            this.init_resolve_func = r;
            this.init_reject_func = j;
        });
    }

    /** 初始化回调 */
    public static GBCommonSDKInitCallBack(code : number , msg : string){
        Logger.error(code , msg);        
        code == 0 ? this.init_resolve_func() : this.init_reject_func(msg);
    }

    /** 登录 */
    public static GBCommonSDK_Login(){
        if(!CC_JSB) return;
        jsb.reflection.callStaticMethod("org/cocos2dx/javascript/AppActivity" , "GBCommonSDK_Login" , "()V");
        return new Promise((r,j)=>{
            this.login_resolve_func = r;
            this.login_reject_func = j;
        });
    }

    /** 登录回调 */
    public static GBCommonSDKLoginCallBack(code : number , userinfo : any){
        Logger.error(code , userinfo);
        code == 0 ? this.login_resolve_func(userinfo) : this.login_reject_func(userinfo);
    }

    /** 登出 */
    public static GBCommonSDK_Logout(){
        if(!CC_JSB) return;
        jsb.reflection.callStaticMethod("org/cocos2dx/javascript/AppActivity" , "GBCommonSDK_Logout" , "()V");
        return new Promise((r,j)=>{
            this.logout_resolve_func = r;
            this.logout_reject_func = j;
        });
    }

    /** 登出回调 */
    public static GBCommonSDKLogoutCallBack(code : number){
        Logger.error(code);
        code == 0 ? this.logout_resolve_func() : this.logout_reject_func();
    }

    /** 支付风控 */
    public static GBCommonSDK_getRiskControlInfo(){
        if(!CC_JSB) return;
        jsb.reflection.callStaticMethod("org/cocos2dx/javascript/AppActivity" , "GBCommonSDK_getRiskControlInfo" , "()V");
        return new Promise((r,j)=>{
            this.risk_resolve_func = r;
            this.risk_reject_func = j;
        });
    }

    /** 风控回调 */
    public static GBCommonSDKRickCallBack(info : any){
        Logger.error(info);
        this.risk_resolve_func(JSON.stringify(info));
    }

    /** 支付 */
    public static GBCommonSDK_Pay(info : string){
        if(!CC_JSB) return;
        jsb.reflection.callStaticMethod("org/cocos2dx/javascript/AppActivity" , "GBCommonSDK_Pay" , "(Ljava/lang/String;)V" , info);
        return new Promise((r,j)=>{
            this.pay_resolve_func = r;
            this.pay_reject_func = j;
        });
    }

    /** 支付回调 */
    public static GBCommonSDKPayCallBack(code : number , payinfo : any){
        Logger.error(code , payinfo);
        code == 0 ? this.pay_resolve_func(payinfo) : this.pay_reject_func(payinfo);
    }
}
if(CC_JSB){
    globalThis["ByteDanceAppHelper"] = ByteDanceAppHelper;
}