import { UserDataMgr } from "../../../System/User/UserDataMgr";
import ComponentBase from "../../../engine/ComponentBase";
import { GameMode, ILevelData } from "../../../gamePlaySystem/GameAttribute";
import Item_leveEntrance from "./Item_leveEntrance";

const { ccclass, property } = cc._decorator;

@ccclass
export default class PageCom extends ComponentBase {

  private layout: cc.Node = null
  private Item_leveEntrance_Node: cc.Node = null;

  private pageIdex: number;
  private _datas: ILevelData[];
  private _gameMode: GameMode;

  private items: Item_leveEntrance[] = [];

  onLoad() {
  }

  SetData(datas: ILevelData[], pageNum: number, gameMode: GameMode) {
    this.pageIdex = pageNum;
    this._datas = datas;
    this._gameMode = gameMode;
    this.AddItem();
  }

  AddItem() {
    let countInPage = this._datas.length;
    for (let i = 0; i < countInPage; i++) {
      if(this._datas[i].level == -1){
        continue;
      }
      this.layout = this.node.getChildByName("Layout");
      this.Item_leveEntrance_Node = this.node.getChildByName("Item_leveEntrance");
      this.Item_leveEntrance_Node.active = false;

      let newN = cc.instantiate(this.Item_leveEntrance_Node);
      newN.active = true;
      this.items[i] = newN.addComponent(Item_leveEntrance).Init().SetData(this._datas[i], this._gameMode);
      this.layout.addChild(newN);
    }
  }


  RefashPageView() {
    for (let i = 0, len = this.items.length; i < len; i++) {
      this.items[i].ReflashView();
    }

  }

  start() {

  }

  // update (dt) {}
}


