import { BasicGameManger } from './BasicGameManger';
import GameData from '../../game/GameData';

export class ZbtGameManger extends BasicGameManger {
    constructor() {
        super();
    }
    
    /** 转跳到关卡 */
    static gotoLevel(level: number, callback?: ()=>any){
        if(GameData.CurGM){
            GameData.CurGM.EndGame();
            GameData.CurGM = null;
        }

        let gm = new ZbtGameManger;
        gm.createGame(level, callback)
        GameData.CurGM = gm;
    }
}
