import BasePlatformAPI from "./BasePlatformAPI";

export default class DeviceAPI extends BasePlatformAPI {

    private static device : DeviceAPI = null;
	public static get Init() : DeviceAPI{
		if(this.device == null){
			this.device = new DeviceAPI();
		}
		return this.device;
	}

    public RequirePrivacyAuthorize(success: Function = ()=>{}, fail: Function = ()=>{}, complete: Function = ()=>{}){
        if(this.api.requirePrivacyAuthorize){
            this.api.requirePrivacyAuthorize({
                success: success,
                fail: fail, // 用户拒绝授权
                complete: complete
            })
        }else{
            success && success();
            complete && complete();
        }
    }

    /**长震动 */
    public VibrateLong(){
        if(!this.api) return;
        this.api.vibrateLong();
    }

    /**短震动 */
    public VibrateShort(){
        if(!this.api) return;
        this.api.vibrateShort();
    }

    /** 复制文本 */
    public SetClipboardData(msg : string){
        if(!this.api) return;
        this.RequirePrivacyAuthorize(() => {
            this.api.setClipboardData({
                data : msg
            });
        })
    }

    /** 抖音用 */
    public OnKeyboardComplete(func : Function){
        if(!this.api) return;
        this.api.onKeyboardComplete(func);
    }
    public OnKeyboardConfirm (func : Function){
        if(!this.api) return;
        this.api.onKeyboardConfirm (func);
    }
    public OffKeyboardComplete(func : Function){
        if(!this.api) return;
        this.api.offKeyboardComplete(func);
    }
    public OffKeyboardConfirm (func : Function){
        if(!this.api) return;
        this.api.offKeyboardConfirm (func);
    }

    /**
     * 当 iOS/Android 向小程序进程发出内存警告时，触发该事件。触发该事件不意味小程序被杀，大部分情况下仅仅是告警，开发者可在收到通知后回收一些不必要资源避免进一步加剧内存紧张
     * @param {*} cbfunc 回调方法
     * @param {*} cbobj 回调类
     */
     public OnMemoryWarning(cbfunc : Function , cbobj : any){
        if(!this.api) return;
        this.api.onMemoryWarning(cbfunc.bind(cbobj));
    }
}