import { AndroidHelper } from "../sdk/AndroidHelper";
import { IOSHelper } from "../sdk/IOSHelper";
import SceneAPI from "../wx_api/SceneAPI";

export default class JSB_ShowToast {

    /** 提示 */
    public static init(){
        SceneAPI.Init.ShowToast = function (info : string , icon: "success" | "loading" | "none",) {
            if(CC_JSB){
                if(cc.sys.os == "Android"){
                    AndroidHelper.ShowToast(info);
                }else if(cc.sys.os == "iOS"){
                    IOSHelper.ShowToast(info);
                }
            }
        }
    }
}