import GameData from "../../GameData";
import VideoAdSystem from "../../../System/VideoAd/VideoAdManager";
import UIData from "../../fgui/GameUIEnum";
import ResourcesManager from "../../../engine/ResourceManager";
import { GrayscaleGradientHelper } from "../../../Tools/GrayscaleGradientHelper";
import { BundleGroupType } from "../../../Const/GameConst";
import LevelPageView from "./LevelPageView";

let isEnterClassifyPage = false;
let lastSelectMode: GameMode = null;
const { ccclass, property } = cc._decorator;

@ccclass
export default class HomeView extends ViewBase {

    private mainPageView: cc.PageView = null;
    private pageNode: cc.Node = null;
    private Label_level: cc.Label;
    gamesPanel: cc.Node;
    pagePanel: cc.Node;
    classifyPanel: cc.Node;
    retClassifyBtn: cc.Node;
	currentGameMode: GameMode;
    classifyList: cc.Node;
    classifyPageView: cc.PageView;
    // private adTimeout: cc.Label;


    onLoad(): void {
        // this.adTimeout = this.getChild(this.node, "adTimeout", cc.Label);
        this.pagePanel = this.getChild(this.node, "pagePanel") as cc.Node;
        this.mainPageView = this.getChild(this.node, "pagePanel/PageView", cc.PageView);
        this.classifyPageView = this.getChild(this.node, "classifyPanel/PageView", cc.PageView);
        this.pageNode = this.getChild(this.node, "pagePanel/myPage");
        this.gamesPanel = this.getChild(this.node, "pagePanel/gamesPanel") as cc.Node;
        this.classifyPanel = this.getChild(this.node, "classifyPanel") as cc.Node;
        this.retClassifyBtn = this.getChild(this.node, "classifyPanel/topPanel/retClassifyBtn");
        this.classifyList = this.getChild(this.node, "classifyPanel/classifyList") as cc.Node;

		this.onAddEvent(this.getChild(this.node, "pagePanel/topPanel/settingBtn"), () => { this.onClick_SettingBtn() });
        this.onAddEvent(this.getChild(this.node, "pagePanel/topPanel/dyBtn"), () => { this.onClick_dyBtn() });
        this.onAddEvent(this.getChild(this.node, "pagePanel/topPanel/rankBtn"), () => { this.onClick_rankBtn() });
        this.onAddEvent(this.getChild(this.node, "pagePanel/topPanel/prizeBtn"), () => { this.onClick_prizeBtn() });
        this.onAddEvent(this.getChild(this.node, "pagePanel/gamesPanel/openHCZB"), () => { this.onClick_openHCZB() });

		this.onAddEvent(this.getChild(this.node, "classifyPanel/topPanel/settingBtn"), () => { this.onClick_SettingBtn() });
        this.onAddEvent(this.getChild(this.node, "classifyPanel/topPanel/retClassifyBtn"), () => { this.onClick_retClassifyBtn() });
        this.initGamesBtn();
    }

    // 是否是主页面的游戏模式
    isMainPageGameMode(gameMode: GameMode): boolean { 
        return this.gamesPanel.getChildByName(gameMode) != null; 
    }

    onClick_openHCZB() {
        this.openClassifyView(false);
    }

    onClick_retClassifyBtn() { 
        if(this.classifyList.active){
            this.openLvPageView();
        }else{
            this.classifyList.active = true;
            this.classifyPageView.node.active = false;
        }
    }

    openClassifyView(isEnterPage: boolean = false) {
        this.classifyPanel.active = true;
        this.classifyPageView.node.active = isEnterPage;
        this.classifyList.active = !isEnterPage;
        this.pagePanel.active = false;
        isEnterClassifyPage = true;
        this.refeshClassifyPanel();
        if(isEnterPage){
            this.ReflashLvList();
        }
    }

    openLvPageView(gameMode?: GameMode){
        isEnterClassifyPage = false;
        this.pagePanel.active = true;
        this.classifyPanel.active = false;
        if(!gameMode){
            gameMode = UserDataMgr.instance.GetSelectedGameMode();
            // 如果按钮中没有选择的游戏模式，就默认第一个模式
            if(!this.gamesPanel.getChildByName(gameMode)){
                gameMode = lastSelectMode || this.gamesPanel.children[0].name as GameMode;
            }
        }
        UserDataMgr.instance.SetSelectedGameMode(gameMode);
        this.currentGameMode = gameMode;
        this.selectGame(gameMode);
        this.ReflashLvList();
    }

	ReflashLvList() {
		let scrip = this.classifyPanel.active ? this.classifyPageView.node.getComponent(LevelPageView) : this.mainPageView.node.getComponent(LevelPageView);
		scrip.ReflashLvList();
	}

    onInitChild() {
        GrayscaleGradientHelper.loadEffect();
        Singleton.SoundSystem.PlayBgm('resources',"sound/home_bgm");

        if(this.isMainPageGameMode(UserDataMgr.instance.GetSelectedGameMode())){
            this.openLvPageView();
        }else{
            this.openClassifyView(true);
        }
    }

    refeshClassifyPanel(){
        let scrollView = this.classifyPanel.getChildByName('classifyList').getComponent(cc.ScrollView);
        let content = scrollView.content;
        let classifyItemTemplate = scrollView.node.getChildByName('classifyItem');
        classifyItemTemplate.active = false;
        
        if(!classifyItemTemplate){
            console.error('未找到 classifyItem 预制体');
            return;
        }

        GameModeInfo.forEach((info, index) => {
            const gameMode = info.mode as GameMode;
            let item = content.getChildByName(gameMode);
            
            if(!item){
                item = cc.instantiate(classifyItemTemplate);
                item.active = true;
                item.name = gameMode;
                item.parent = content;
            }
            
            this.setupClassifyItem(item, gameMode, info.title);
        });
    }

    private async setupClassifyItem(item: cc.Node, gameMode: GameMode, title: string){
        const isUnlocked = UserDataMgr.instance.IsGameModeUnlocked(gameMode);
        const passedCount = UserDataMgr.instance.GetPassedLevelCount(gameMode);
        const totalCount = UserDataMgr.instance.GetTotalLevelCount(gameMode);
        const adCount = UserDataMgr.instance.GetGameModeAdCount(gameMode);
        
        const titleLabel = item.getChildByName('title');
        titleLabel.getComponent(cc.Label).string = title;
        
        const progressBar = item.getChildByName('progressBar');
        const progress = totalCount > 0 ? passedCount / totalCount : 0;
        progressBar.getComponent(cc.ProgressBar).progress = progress;
        
        const label = progressBar.getChildByName('label');
        label.getComponent(cc.Label).string = `${passedCount}/${totalCount}`;
        
        const lockNode = item.getChildByName('lock');
        const adNode = item.getChildByName('ad');
        
        const spr = item.getChildByName('img').getComponent(cc.Sprite);
        const iconUrl = UIData.GetGameModeIcon(gameMode);
        ResourcesManager.instance.loadResByBundleNameAndPaths('common', iconUrl, cc.SpriteFrame, async (res) => {
            if(res){
                if(spr.isValid){
                    spr.spriteFrame = res;
                    await GrayscaleGradientHelper.applyToSprite(spr, progress);
                }
            }else{
                console.error(`未找到游戏模式图标 ${UIData.GetGameModeIcon(gameMode)}`);
            }
        }, BundleGroupType.Game);

        if(isUnlocked){
            lockNode.active = false;
            adNode.active = false;
            progressBar.active = true;
        } else {
            lockNode.active = true;
            adNode.active = true;
            progressBar.active = false;
            const adLabel = adNode.getChildByName('label');
            adLabel.getComponent(cc.Label).string = `(${adCount}/2)`;
        }
        
        item.off(cc.Node.EventType.TOUCH_END);
        item.on(cc.Node.EventType.TOUCH_END, () => {
            this.onClickClassifyItem(gameMode);
        });
    }

    private async onClickClassifyItem(gameMode: GameMode){
        const isUnlocked = UserDataMgr.instance.IsGameModeUnlocked(gameMode);
        
        if(isUnlocked){
            UserDataMgr.instance.SetSelectedGameMode(gameMode);
            this.openClassifyView(true);
        } else {
            const success = await VideoAdSystem.PlayerVideoAd();
            if(!success) return;
            
            UserDataMgr.instance.AddGameModeAdCount(gameMode);
            
            if(UserDataMgr.instance.IsGameModeUnlocked(gameMode)){
                Singleton.GameEventSystem.dispatch(GameEvent.UP_HOME_UI);
            }
            
            this.refeshClassifyPanel();
        }
    }

    
    /** 点击每日奖励 */
    onClick_dyBtn(){
        UIManager.instance.showView(ViewConfig.TiktokView);
    }

    /** 点击排行榜 */
    onClick_rankBtn(){
        // UIManager.instance.showView(ViewConfig.ExtraTimeView);
    }

    /** 点击奖励 */
    onClick_prizeBtn(){
        UIManager.instance.showView(ViewConfig.DyRewardView);
    }

    /** 选择游戏类型，更新对应关卡列表 */
    initGamesBtn(){
        this.gamesPanel.children.forEach((node)=>{

            GameMode[node.name] && node.on(cc.Node.EventType.TOUCH_END, ()=>{
                // 按钮名字就是游戏模式
                this.selectGame(node.name as GameMode);
            })
        })
    }
    
    private lastSelectNode: cc.Node = null;
    /** 主页面: 突出选中的游戏类型 */
    selectGame(gameMode: GameMode) {
        // 记录到用户数据管理类
        UserDataMgr.instance.SetSelectedGameMode(gameMode);
        this.currentGameMode = gameMode;
        
        if (this.lastSelectNode && this.lastSelectNode.name === gameMode) {
            return;
        }
        let selectFunc = (node: cc.Node, isSeleced: boolean)=>{
            node.stopAllActions();
            node.getChildByName('label').color = isSeleced ? cc.color(93, 0, 200) : cc.color(132, 46, 0);
            node.getChildByName('bg2').active = isSeleced;
            node.getChildByName('bg1').active = !isSeleced;
            cc.tween(node)
                .to(0.1, isSeleced ? 
                    { scale: 1.1, y: 15 } : 
                    { scale: 1, y: 0 }, 
                    { easing: 'sineOut' })
                .call(() => {
                })
                .start();
        } 
        let selectedNode = this.gamesPanel.getChildByName(gameMode);
        if(selectedNode){
            // 恢复上一个节点缩放
            this.lastSelectNode && selectFunc(this.lastSelectNode, false)
            this.lastSelectNode = selectedNode;
            // 放大当前节点
            selectFunc(selectedNode, true);
            lastSelectMode = gameMode;
        }
        
        this.ReflashLvList();
    }

	onEnable(){
		// Timer.loop(1000, this, ()=>{
		// 	let unlockTime = UserDataMgr.instance.GetUnlockTime();
		// 	if(!unlockTime){
		// 		// this.adTimeout.node.active = false;
		// 		return;
		// 	}
        //     // 剩余时间
        //     let time = unlockTime - Date.now();
		// 	// this.adTimeout.node.active = true;
        //     // 倒计时: 24:00:00
		// 	// this.adTimeout.string = `解锁倒计时: ${DateUtil.formatHourMinSecondStr(time + 57600000)}`;
		// })
	}

    onDisable(): void {
        Singleton.GameEventSystem.clear(this);
        Timer.clearAll(this);
    }

    private onClick_SettingBtn() {
        UIManager.instance.showView(ViewConfig.SettingView);
    }
}
